window.KJV1769_STRONG_BOOKS["2Cor"] = {"osis":"2Cor","book":"고린도후서","verses":{"1:1":{"text":"Paul, an apostle of Jesus Christ by the will of God, and Timothy our brother, unto the church of God which is at Corinth, with all the saints which are in all Achaia:","words":[["G3972","Paul",0,4],["G0652","an apostle",6,16],["G2424","of Jesus",17,25],["G5547","Christ",26,32],["G1223","by",33,35],["G2307","the will",36,44],["G2316","of God",45,51],["G2532","and",53,56],["G5095","Timothy",57,64],["G0080","our brother",65,76],["G1577","unto the church",78,93],["G2316","of God",94,100],["G3588","which",101,106],["G5607","is",107,109],["G1722","at",110,112],["G2882","Corinth",113,120],["G4862","with",122,126],["G3956","all",127,130],["G0040","the saints",131,141],["G3588","which",142,147],["G5607","are",148,151],["G1722","in",152,154],["G3650","all",155,158],["G0882","Achaia",159,165]]},"1:2":{"text":"Grace be to you and peace from God our Father, and from the Lord Jesus Christ.","words":[["G5485","Grace",0,5],["G5213","be to you",6,15],["G2532","and",16,19],["G1515","peace",20,25],["G0575","from",26,30],["G2316","God",31,34],["G2257","our",35,38],["G3962","Father",39,45],["G2532","and",47,50],["G2962","from the Lord",51,64],["G2424","Jesus",65,70],["G5547","Christ",71,77]]},"1:3":{"text":"Blessed be God, even the Father of our Lord Jesus Christ, the Father of mercies, and the God of all comfort;","words":[["G2128","Blessed",0,7],["G2316","be God",8,14],["G2532","even",16,20],["G3962","the Father",21,31],["G2257","of our",32,38],["G2962","Lord",39,43],["G2424","Jesus",44,49],["G5547","Christ",50,56],["G3962","the Father",58,68],["G3628","of mercies",69,79],["G2532","and",81,84],["G2316","the God",85,92],["G3956","of all",93,99],["G3874","comfort",100,107]]},"1:4":{"text":"Who comforteth us in all our tribulation, that we may be able to comfort them which are in any trouble, by the comfort wherewith we ourselves are comforted of God.","words":[["G3588","Who",0,3],["G3870","comforteth",4,14],["G2248","us",15,17],["G1909","in",18,20],["G3956","all",21,24],["G2257","our",25,28],["G2347","tribulation",29,40],["G1519","that",42,46],["G2248","we",47,49],["G1410","may be able",50,61],["G3870","to comfort",62,72],["G1722","them which are in",73,90],["G3956","any",91,94],["G2347","trouble",95,102],["G1223","by",104,106],["G3874","the comfort",107,118],["G3739","wherewith",119,128],["G3870","we",129,131],["G0846","ourselves",132,141],["G3870","are comforted",142,155],["G5259","of",156,158],["G2316","God",159,162]]},"1:5":{"text":"For as the sufferings of Christ abound in us, so our consolation also aboundeth by Christ.","words":[["G3754","For",0,3],["G2531","as",4,6],["G3804","the sufferings",7,21],["G5547","of Christ",22,31],["G4052","abound",32,38],["G1519","in",39,41],["G2248","us",42,44],["G3779","so",46,48],["G2257","our",49,52],["G3874","consolation",53,64],["G2532","also",65,69],["G4052","aboundeth",70,79],["G1223","by",80,82],["G5547","Christ",83,89]]},"1:6":{"text":"And whether we be afflicted, it is for your consolation and salvation, which is effectual in the enduring of the same sufferings which we also suffer: or whether we be comforted, it is for your consolation and salvation.","words":[["G1161","And",0,3],["G1535","whether",4,11],["G2346","we be afflicted",12,27],["G5228","it is for",29,38],["G5216","your",39,43],["G3874","consolation",44,55],["G2532","and",56,59],["G4991","salvation",60,69],["G3588","which",71,76],["G1754","is effectual",77,89],["G1722","in",90,92],["G5281","the enduring",93,105],["G0846","of the same",106,117],["G3804","sufferings",118,128],["G3739","which",129,134],["G2249","we",135,137],["G2532","also",138,142],["G3958","suffer",143,149],["G1535","or whether",151,161],["G3870","we be comforted",162,177],["G5228","it is for",179,188],["G5216","your",189,193],["G3874","consolation",194,205],["G2532","and",206,209],["G4991","salvation",210,219]]},"1:7":{"text":"And our hope of you is stedfast, knowing, that as ye are partakers of the sufferings, so shall ye be also of the consolation.","words":[["G2532","And",0,3],["G2257","our",4,7],["G1680","hope",8,12],["G5228","of",13,15],["G5216","you",16,19],["G0949","is stedfast",20,31],["G1492","knowing",33,40],["G3754","that",42,46],["G5618","as",47,49],["G2075","ye are",50,56],["G2844","partakers",57,66],["G3804","of the sufferings",67,84],["G3779","so",86,88],["G2532","shall ye be also",89,105],["G3874","of the consolation",106,124]]},"1:8":{"text":"For we would not, brethren, have you ignorant of our trouble which came to us in Asia, that we were pressed out of measure, above strength, insomuch that we despaired even of life:","words":[["G1063","For",0,3],["G2309","we would",4,12],["G3756","not",13,16],["G0080","brethren",18,26],["G0050","have",28,32],["G5209","you",33,36],["G0050","ignorant",37,45],["G5228","of",46,48],["G2257","our",49,52],["G2347","trouble",53,60],["G3588","which",61,66],["G1096","came",67,71],["G2254","to us",72,77],["G1722","in",78,80],["G0773","Asia",81,85],["G3754","that",87,91],["G2596","we were pressed",92,107],["G0916","out",108,111],["G5236","of measure",112,122],["G5228","above",124,129],["G1411","strength",130,138],["G5620","insomuch",140,148],["G2248","that we",149,156],["G1820","despaired",157,166],["G2532","even",167,171],["G2198","of life",172,179]]},"1:9":{"text":"But we had the sentence of death in ourselves, that we should not trust in ourselves, but in God which raiseth the dead:","words":[["G0235","But",0,3],["G0846","But",0,3],["G2192","we had",4,10],["G0610","the sentence",11,23],["G2288","of death",24,32],["G1722","in",33,35],["G1438","ourselves",36,45],["G3363","that",47,51],["G3982","we should",52,61],["G3363","not",62,65],["G3982","trust",66,71],["G1909","in",72,74],["G1438","ourselves",75,84],["G5600","ourselves",75,84],["G0235","but",86,89],["G1909","in",90,92],["G2316","God",93,96],["G3588","which",97,102],["G1453","raiseth",103,110],["G3498","the dead",111,119]]},"1:10":{"text":"Who delivered us from so great a death, and doth deliver: in whom we trust that he will yet deliver us;","words":[["G3739","Who",0,3],["G4506","delivered",4,13],["G2248","us",14,16],["G1537","from",17,21],["G5082","so great",22,30],["G2288","a death",31,38],["G2532","and",40,43],["G4506","doth deliver",44,56],["G1519","in",58,60],["G3739","whom",61,65],["G1679","we trust",66,74],["G3754","that",75,79],["G4506","he will",80,87],["G2532","he will",80,87],["G2089","yet",88,91],["G4506","deliver",92,99]]},"1:11":{"text":"Ye also helping together by prayer for us, that for the gift bestowed upon us by the means of many persons thanks may be given by many on our behalf.","words":[["G5216","Ye",0,2],["G2532","also",3,7],["G4943","helping together",8,24],["G1162","by prayer",25,34],["G5228","for",35,38],["G2257","us",39,41],["G2443","that",43,47],["G5486","for the gift",48,60],["G1519","bestowed upon",61,74],["G2248","us",75,77],["G1537","by",78,80],["G4183","the means of many",81,98],["G4383","persons",99,106],["G2168","thanks may be",107,120],["G5228","given",121,126],["G1223","by",127,129],["G4183","many",130,134],["G2257","on our behalf",135,148]]},"1:12":{"text":"For our rejoicing is this, the testimony of our conscience, that in simplicity and godly sincerity, not with fleshly wisdom, but by the grace of God, we have had our conversation in the world, and more abundantly to you-ward.","words":[["G1063","For",0,3],["G2257","our",4,7],["G2746","rejoicing",8,17],["G2076","is",18,20],["G3778","this",21,25],["G3142","the testimony",27,40],["G2257","of our",41,47],["G4893","conscience",48,58],["G3754","that",60,64],["G1722","in",65,67],["G0572","simplicity",68,78],["G2532","and",79,82],["G2316","godly",83,88],["G1505","sincerity",89,98],["G3756","not",100,103],["G1722","with",104,108],["G4559","fleshly",109,116],["G4678","wisdom",117,123],["G0235","but",125,128],["G1722","by",129,131],["G5485","the grace",132,141],["G2316","of God",142,148],["G0390","we have had our conversation",150,178],["G1722","in",179,181],["G2889","the world",182,191],["G1161","and",193,196],["G4056","more abundantly",197,212],["G4314","to",213,215],["G5209","you-ward",216,224]]},"1:13":{"text":"For we write none other things unto you, than what ye read or acknowledge; and I trust ye shall acknowledge even to the end;","words":[["G1063","For",0,3],["G1125","we write",4,12],["G3756","none",13,17],["G0243","other things",18,30],["G5213","unto you",31,39],["G0235","than",41,45],["G2228","than",41,45],["G3739","what",46,50],["G0314","ye read",51,58],["G2228","or",59,61],["G2532","or",59,61],["G1921","acknowledge",62,73],["G1161","and",75,78],["G1679","I trust",79,86],["G3754","I trust",79,86],["G1921","ye shall acknowledge",87,107],["G2532","even",108,112],["G2193","to",113,115],["G5056","the end",116,123]]},"1:14":{"text":"As also ye have acknowledged us in part, that we are your rejoicing, even as ye also are ours in the day of the Lord Jesus.","words":[["G2531","As",0,2],["G2532","also",3,7],["G1921","ye have acknowledged",8,28],["G2248","us",29,31],["G0575","in",32,34],["G3313","part",35,39],["G3754","that",41,45],["G2070","we are",46,52],["G5216","your",53,57],["G2745","rejoicing",58,67],["G2509","even as",69,76],["G5210","ye",77,79],["G2532","also",80,84],["G2257","are ours",85,93],["G1722","in",94,96],["G2250","the day",97,104],["G2962","of the Lord",105,116],["G2424","Jesus",117,122]]},"1:15":{"text":"And in this confidence I was minded to come unto you before, that ye might have a second benefit;","words":[["G2532","And",0,3],["G5026","in this",4,11],["G4006","confidence",12,22],["G1014","I was minded",23,35],["G2064","to come",36,43],["G4314","unto",44,48],["G5209","you",49,52],["G4386","before",53,59],["G2443","that",61,65],["G2192","ye might have",66,79],["G1208","a second",80,88],["G5485","benefit",89,96]]},"1:16":{"text":"And to pass by you into Macedonia, and to come again out of Macedonia unto you, and of you to be brought on my way toward Judaea.","words":[["G2532","And",0,3],["G1330","to pass",4,11],["G1223","by",12,14],["G5216","you",15,18],["G1519","into",19,23],["G3109","Macedonia",24,33],["G2532","and",35,38],["G2064","to come",39,46],["G3825","again",47,52],["G0575","out of",53,59],["G3109","Macedonia",60,69],["G4314","unto",70,74],["G5209","you",75,78],["G2532","and",80,83],["G5259","of",84,86],["G5216","you",87,90],["G4311","to be brought on my way",91,114],["G1519","toward",115,121],["G2449","Judaea",122,128]]},"1:17":{"text":"When I therefore was thus minded, did I use lightness? or the things that I purpose, do I purpose according to the flesh, that with me there should be yea yea, and nay nay?","words":[["G1011","When I",0,6],["G3767","therefore",7,16],["G1011","was",17,20],["G5124","thus",21,25],["G1011","minded",26,32],["G3385","did I use",34,43],["G0686","did I use",34,43],["G5530","did I use",34,43],["G1644","lightness",44,53],["G2228","or",55,57],["G3739","the things that",58,73],["G1011","I purpose",74,83],["G1011","do I purpose",85,97],["G2596","according",98,107],["G4561","to the flesh",108,120],["G2443","that",122,126],["G3844","with",127,131],["G1698","me",132,134],["G5600","there should be",135,150],["G3483","yea",151,154],["G3483","yea",155,158],["G2532","and",160,163],["G3756","nay",164,167],["G3756","nay",168,171]]},"1:18":{"text":"But as God is true, our word toward you was not yea and nay.","words":[["G1161","But",0,3],["G2316","as God",4,10],["G4103","is true",11,18],["G3754","",-1,-1],["G2257","our",20,23],["G3056","word",24,28],["G4314","toward",29,35],["G5209","you",36,39],["G1096","was",40,43],["G3756","not",44,47],["G3483","yea",48,51],["G2532","and",52,55],["G3756","nay",56,59]]},"1:19":{"text":"For the Son of God, Jesus Christ, who was preached among you by us, even by me and Silvanus and Timotheus, was not yea and nay, but in him was yea.","words":[["G1063","For",0,3],["G5207","the Son",4,11],["G2316","of God",12,18],["G2424","Jesus",20,25],["G5547","Christ",26,32],["G3588","who",34,37],["G2784","was preached",38,50],["G1722","among",51,56],["G5213","you",57,60],["G1223","by",61,63],["G2257","us",64,66],["G1223","even by",68,75],["G1700","me",76,78],["G2532","and",79,82],["G4610","Silvanus",83,91],["G2532","and",92,95],["G5095","Timotheus",96,105],["G1096","was",107,110],["G3756","not",111,114],["G3483","yea",115,118],["G2532","and",119,122],["G3756","nay",123,126],["G0235","but",128,131],["G1722","in",132,134],["G0846","him",135,138],["G1096","was",139,142],["G3483","yea",143,146]]},"1:20":{"text":"For all the promises of God in him are yea, and in him Amen, unto the glory of God by us.","words":[["G1063","For",0,3],["G3745","all",4,7],["G1860","the promises",8,20],["G2316","of God",21,27],["G1722","in",28,30],["G0846","him",31,34],["G3483","are yea",35,42],["G2532","and",44,47],["G1722","in",48,50],["G0846","him",51,54],["G0281","Amen",55,59],["G4314","unto",61,65],["G1391","the glory",66,75],["G2316","of God",76,82],["G1223","by",83,85],["G2257","us",86,88]]},"1:21":{"text":"Now he which stablisheth us with you in Christ, and hath anointed us, is God;","words":[["G1161","Now",0,3],["G0950","he which stablisheth",4,24],["G2248","us",25,27],["G4862","with",28,32],["G5213","you",33,36],["G1519","in",37,39],["G5547","Christ",40,46],["G2532","and",48,51],["G5548","hath anointed",52,65],["G2248","us",66,68],["G2316","is God",70,76]]},"1:22":{"text":"Who hath also sealed us, and given the earnest of the Spirit in our hearts.","words":[["G3588","Who",0,3],["G4972","hath",4,8],["G2532","also",9,13],["G4972","sealed",14,20],["G2248","us",21,23],["G2532","and",25,28],["G1325","given",29,34],["G0728","the earnest",35,46],["G4151","of the Spirit",47,60],["G1722","in",61,63],["G2257","our",64,67],["G2588","hearts",68,74]]},"1:23":{"text":"Moreover I call God for a record upon my soul, that to spare you I came not as yet unto Corinth.","words":[["G1161","Moreover",0,8],["G1473","I",9,10],["G1941","call",11,15],["G2316","God",16,19],["G3144","for a record",20,32],["G1909","upon",33,37],["G1699","my",38,40],["G5590","soul",41,45],["G3754","that",47,51],["G5339","to spare",52,60],["G5216","you",61,64],["G2064","I came",65,71],["G3765","not as yet",72,82],["G1519","unto",83,87],["G2882","Corinth",88,95]]},"1:24":{"text":"Not for that we have dominion over your faith, but are helpers of your joy: for by faith ye stand.","words":[["G3756","Not",0,3],["G3754","for that",4,12],["G2961","we have dominion over",13,34],["G5216","your",35,39],["G4102","faith",40,45],["G0235","but",47,50],["G2070","are",51,54],["G4904","helpers",55,62],["G5216","of your",63,70],["G5479","joy",71,74],["G1063","for",76,79],["G4102","by faith",80,88],["G2476","ye stand",89,97]]},"2:1":{"text":"But I determined this with myself, that I would not come again to you in heaviness.","words":[["G1161","But",0,3],["G2919","I determined",4,16],["G5124","this",17,21],["G1683","with myself",22,33],["G2064","that I would",35,47],["G3361","not",48,51],["G2064","come",52,56],["G3825","again",57,62],["G4314","to",63,65],["G5209","you",66,69],["G1722","in",70,72],["G3077","heaviness",73,82]]},"2:2":{"text":"For if I make you sorry, who is he then that maketh me glad, but the same which is made sorry by me?","words":[["G1063","For",0,3],["G1487","if",4,6],["G1473","I",7,8],["G3076","make",9,13],["G5209","you",14,17],["G3076","sorry",18,23],["G5101","who",25,28],["G2076","is he",29,34],["G2532","then",35,39],["G2165","that maketh",40,51],["G3165","me",52,54],["G2165","glad",55,59],["G1508","but",61,64],["G3076","the same which is made sorry",65,93],["G1537","by",94,96],["G1700","me",97,99]]},"2:3":{"text":"And I wrote this same unto you, lest, when I came, I should have sorrow from them of whom I ought to rejoice; having confidence in you all, that my joy is the joy of you all.","words":[["G2532","And",0,3],["G1125","I wrote",4,11],["G5124","this",12,16],["G0846","same",17,21],["G5213","unto you",22,30],["G3363","lest",32,36],["G2064","when I came",38,49],["G2192","I should have",51,64],["G3077","sorrow",65,71],["G0575","from",72,76],["G3739","them of whom",77,89],["G3165","I",90,91],["G1163","ought",92,97],["G5463","to rejoice",98,108],["G3982","having confidence",110,127],["G1909","in",128,130],["G5209","you",131,134],["G3956","all",135,138],["G3754","that",140,144],["G1699","my",145,147],["G5479","joy",148,151],["G2076","is",152,154],["G5216","the joy of you",155,169],["G3956","all",170,173]]},"2:4":{"text":"For out of much affliction and anguish of heart I wrote unto you with many tears; not that ye should be grieved, but that ye might know the love which I have more abundantly unto you.","words":[["G1063","For",0,3],["G1537","out of",4,10],["G4183","much",11,15],["G2347","affliction",16,26],["G2532","and",27,30],["G4928","anguish",31,38],["G2588","of heart",39,47],["G1125","I wrote",48,55],["G5213","unto you",56,64],["G1223","with",65,69],["G4183","many",70,74],["G1144","tears",75,80],["G3756","not",82,85],["G2443","that",86,90],["G3076","ye should be grieved",91,111],["G0235","but",113,116],["G2443","that",117,121],["G1097","ye might know",122,135],["G0026","the love",136,144],["G3739","which",145,150],["G2192","I have",151,157],["G4056","more abundantly",158,173],["G1519","unto",174,178],["G5209","you",179,182]]},"2:5":{"text":"But if any have caused grief, he hath not grieved me, but in part: that I may not overcharge you all.","words":[["G1161","But",0,3],["G1536","if any",4,10],["G3076","have caused grief",11,28],["G3076","he hath",30,37],["G3756","not",38,41],["G3076","grieved",42,49],["G1691","me",50,52],["G0235","but",54,57],["G0575","in",58,60],["G3313","part",61,65],["G3363","that",67,71],["G1912","I may",72,77],["G3363","not",78,81],["G1912","overcharge",82,92],["G5209","you",93,96],["G3956","all",97,100]]},"2:6":{"text":"Sufficient to such a man is this punishment, which was inflicted of many.","words":[["G2425","Sufficient",0,10],["G5108","to such a man",11,24],["G3778","is this",25,32],["G2009","punishment",33,43],["G3588","which",45,50],["G5259","was inflicted of",51,67],["G4119","many",68,72]]},"2:7":{"text":"So that contrariwise ye ought rather to forgive him, and comfort him, lest perhaps such a one should be swallowed up with overmuch sorrow.","words":[["G5620","So",0,2],["G5121","that contrariwise",3,20],["G5209","ye",21,23],["G3123","ought rather",24,36],["G5483","to forgive",37,47],["G2532","him, and",48,56],["G3870","comfort",57,64],["G3381","him, lest",65,74],["G4458","perhaps",75,82],["G5108","such a one",83,93],["G2666","should be swallowed up",94,116],["G4055","with overmuch",117,130],["G3077","sorrow",131,137]]},"2:8":{"text":"Wherefore I beseech you that ye would confirm your love toward him.","words":[["G1352","Wherefore",0,9],["G3870","I beseech",10,19],["G5209","you",20,23],["G2964","that ye would confirm",24,45],["G0026","your love",46,55],["G1519","toward",56,62],["G0846","him",63,66]]},"2:9":{"text":"For to this end also did I write, that I might know the proof of you, whether ye be obedient in all things.","words":[["G1063","For",0,3],["G1519","to",4,6],["G5124","this end",7,15],["G2532","also",16,20],["G1125","did I write",21,32],["G2443","that",34,38],["G1097","I might know",39,51],["G1382","the proof",52,61],["G5216","of you",62,68],["G1487","whether",70,77],["G2075","ye be",78,83],["G5255","obedient",84,92],["G1519","in",93,95],["G3956","all things",96,106]]},"2:10":{"text":"To whom ye forgive any thing, I forgive also: for if I forgave any thing, to whom I forgave it, for your sakes forgave I it in the person of Christ;","words":[["G1161","",-1,-1],["G3739","To whom",0,7],["G5483","ye forgive",8,18],["G5100","any thing",19,28],["G1473","I",30,31],["G2532","forgive also",32,44],["G2532","for",46,49],["G1063","for",46,49],["G1473","if I",50,54],["G5483","forgave",55,62],["G1536","any thing",63,72],["G3739","to whom",74,81],["G5483","I forgave",82,91],["G1223","it, for your sakes",92,110],["G5209","it, for your sakes",92,110],["G1722","forgave I it in",111,126],["G4383","the person",127,137],["G5547","of Christ",138,147]]},"2:11":{"text":"Lest Satan should get an advantage of us: for we are not ignorant of his devices.","words":[["G3363","Lest",0,4],["G5259","Satan",5,10],["G4567","Satan",5,10],["G4122","should get an advantage of us",11,40],["G1063","for",42,45],["G3756","we are not",46,56],["G0050","ignorant",57,65],["G0846","of his",66,72],["G3540","devices",73,80]]},"2:12":{"text":"Furthermore, when I came to Troas to preach Christ's gospel, and a door was opened unto me of the Lord,","words":[["G1161","Furthermore",0,11],["G2064","when I came",13,24],["G1519","to",25,27],["G5174","Troas",28,33],["G1519","to",34,36],["G5547","preach Christ's",37,52],["G2098","gospel",53,59],["G2532","and",61,64],["G2374","a door",65,71],["G0455","was opened",72,82],["G3427","unto me",83,90],["G1722","of",91,93],["G2962","the Lord",94,102]]},"2:13":{"text":"I had no rest in my spirit, because I found not Titus my brother: but taking my leave of them, I went from thence into Macedonia.","words":[["G2192","I had",0,5],["G3756","no",6,8],["G0425","rest",9,13],["G3450","in my",14,19],["G4151","spirit",20,26],["G3165","because I",28,37],["G2147","found",38,43],["G3361","not",44,47],["G5103","Titus",48,53],["G3450","my",54,56],["G0080","brother",57,64],["G0235","but",66,69],["G0657","taking my leave",70,85],["G0846","of them",86,93],["G1831","I went from thence",95,113],["G1519","into",114,118],["G3109","Macedonia",119,128]]},"2:14":{"text":"Now thanks be unto God, which always causeth us to triumph in Christ, and maketh manifest the savour of his knowledge by us in every place.","words":[["G1161","Now",0,3],["G5485","thanks",4,10],["G2316","be unto God",11,22],["G3842","which always",24,36],["G2358","causeth",37,44],["G2248","us",45,47],["G2358","to triumph",48,58],["G1722","in",59,61],["G5547","Christ",62,68],["G2532","and",70,73],["G5319","maketh manifest",74,89],["G3744","the savour",90,100],["G0846","of his",101,107],["G1108","knowledge",108,117],["G1223","by",118,120],["G2257","us",121,123],["G1722","in",124,126],["G3956","every",127,132],["G5117","place",133,138]]},"2:15":{"text":"For we are unto God a sweet savour of Christ, in them that are saved, and in them that perish:","words":[["G3754","For",0,3],["G2070","we are",4,10],["G2316","unto God",11,19],["G2175","a sweet savour",20,34],["G5547","of Christ",35,44],["G1722","in",46,48],["G4982","them that are saved",49,68],["G2532","and",70,73],["G1722","in",74,76],["G0622","them that perish",77,93]]},"2:16":{"text":"To the one we are the savour of death unto death; and to the other the savour of life unto life. And who is sufficient for these things?","words":[["G3739","To",0,2],["G3303","the one",3,10],["G3744","we are the savour",11,28],["G2288","of death",29,37],["G1519","unto",38,42],["G2288","death",43,48],["G1161","and",50,53],["G3739","to the other",54,66],["G3744","the savour",67,77],["G2222","of life",78,85],["G1519","unto",86,90],["G2222","life",91,95],["G2532","And",97,100],["G5101","who",101,104],["G2425","is sufficient",105,118],["G4314","for",119,122],["G5023","these things",123,135]]},"2:17":{"text":"For we are not as many, which corrupt the word of God: but as of sincerity, but as of God, in the sight of God speak we in Christ.","words":[["G1063","For",0,3],["G2070","we are",4,10],["G3756","not",11,14],["G5613","as",15,17],["G4183","many",18,22],["G2585","which corrupt",24,37],["G3056","the word",38,46],["G2316","of God",47,53],["G0235","but",55,58],["G5613","as",59,61],["G1537","of",62,64],["G1505","sincerity",65,74],["G0235","but",76,79],["G5613","as",80,82],["G1537","of",83,85],["G2316","God",86,89],["G2714","in the sight",91,103],["G2316","of God",104,110],["G2980","speak we",111,119],["G1722","in",120,122],["G5547","Christ",123,129]]},"3:1":{"text":"Do we begin again to commend ourselves? or need we, as some others, epistles of commendation to you, or letters of commendation from you?","words":[["G0756","Do we begin",0,11],["G3825","again",12,17],["G4921","to commend",18,28],["G1438","ourselves",29,38],["G1508","or",40,42],["G5535","need we",43,50],["G5613","as",52,54],["G5100","some",55,59],["G1992","others, epistles",60,76],["G4956","of commendation",77,92],["G4314","to",93,95],["G5209","you",96,99],["G2228","or",101,103],["G4956","letters of commendation",104,127],["G1537","from",128,132],["G5216","you",133,136]]},"3:2":{"text":"Ye are our epistle written in our hearts, known and read of all men:","words":[["G5210","Ye",0,2],["G2075","are",3,6],["G2257","our",7,10],["G1992","epistle",11,18],["G1449","written",19,26],["G1722","in",27,29],["G2257","our",30,33],["G2588","hearts",34,40],["G1097","known",42,47],["G2532","and",48,51],["G0314","read",52,56],["G5259","of",57,59],["G3956","all",60,63],["G0444","men",64,67]]},"3:3":{"text":"Forasmuch as ye are manifestly declared to be the epistle of Christ ministered by us, written not with ink, but with the Spirit of the living God; not in tables of stone, but in fleshy tables of the heart.","words":[["G5319","Forasmuch as ye are manifestly declared",0,39],["G3754","to",40,42],["G2075","be",43,45],["G1992","the epistle",46,57],["G5547","of Christ",58,67],["G1247","ministered",68,78],["G5259","by",79,81],["G2257","us",82,84],["G1449","written",86,93],["G3756","not",94,97],["G3188","with ink",98,106],["G0235","but",108,111],["G4151","with the Spirit",112,127],["G2198","of the living",128,141],["G2316","God",142,145],["G3756","not",147,150],["G1722","in",151,153],["G4109","tables",154,160],["G3035","of stone",161,169],["G0235","but",171,174],["G1722","in",175,177],["G4560","fleshy",178,184],["G4109","tables",185,191],["G2588","of the heart",192,204]]},"3:4":{"text":"And such trust have we through Christ to God-ward:","words":[["G1161","And",0,3],["G5108","such",4,8],["G4006","trust",9,14],["G2192","have we",15,22],["G1223","through",23,30],["G5547","Christ",31,37],["G4314","to",38,40],["G2316","God-ward",41,49]]},"3:5":{"text":"Not that we are sufficient of ourselves to think any thing as of ourselves; but our sufficiency is of God;","words":[["G3756","Not",0,3],["G3754","that",4,8],["G2070","we are",9,15],["G2425","sufficient",16,26],["G0575","of",27,29],["G1438","ourselves",30,39],["G3049","to think",40,48],["G5100","any thing",49,58],["G5613","as",59,61],["G1537","of",62,64],["G1438","ourselves",65,74],["G0235","but",76,79],["G2257","our",80,83],["G2426","sufficiency",84,95],["G1537","is of",96,101],["G2316","God",102,105]]},"3:6":{"text":"Who also hath made us able ministers of the new testament; not of the letter, but of the spirit: for the letter killeth, but the spirit giveth life.","words":[["G3739","Who",0,3],["G2532","also",4,8],["G2427","hath made",9,18],["G2248","us",19,21],["G2427","able",22,26],["G1249","ministers",27,36],["G2537","of the new",37,47],["G1242","testament",48,57],["G3756","not",59,62],["G1121","of the letter",63,76],["G0235","but",78,81],["G4151","of the spirit",82,95],["G1063","for",97,100],["G1121","the letter",101,111],["G0615","killeth",112,119],["G1161","but",121,124],["G4151","the spirit",125,135],["G2227","giveth life",136,147]]},"3:7":{"text":"But if the ministration of death, written and engraven in stones, was glorious, so that the children of Israel could not stedfastly behold the face of Moses for the glory of his countenance; which glory was to be done away:","words":[["G1161","But",0,3],["G1487","if",4,6],["G1248","the ministration",7,23],["G2288","of death",24,32],["G1722","written",34,41],["G1121","written",34,41],["G1795","and engraven",42,54],["G1722","in",55,57],["G3037","stones",58,64],["G1096","was",66,69],["G1722","glorious",70,78],["G1391","glorious",70,78],["G5620","so",80,82],["G5207","that the children",83,100],["G2474","of Israel",101,110],["G1410","could",111,116],["G3361","not",117,120],["G0816","stedfastly behold",121,138],["G1519","the face",139,147],["G4383","the face",139,147],["G3475","of Moses",148,156],["G1223","for",157,160],["G1391","the glory",161,170],["G0846","of his",171,177],["G4383","countenance",178,189],["G3588","which",191,196],["G2673","glory was to be done away",197,222]]},"3:8":{"text":"How shall not the ministration of the spirit be rather glorious?","words":[["G4459","How",0,3],["G1248","shall",4,9],["G3780","not",10,13],["G1248","the ministration",14,30],["G4151","of the spirit",31,44],["G2071","be",45,47],["G3123","rather",48,54],["G1722","rather",48,54],["G1391","glorious",55,63]]},"3:9":{"text":"For if the ministration of condemnation be glory, much more doth the ministration of righteousness exceed in glory.","words":[["G1063","For",0,3],["G1487","if",4,6],["G1248","the ministration",7,23],["G2633","of condemnation",24,39],["G1391","be glory",40,48],["G4183","much",50,54],["G3123","more",55,59],["G1248","doth the ministration",60,81],["G1343","of righteousness",82,98],["G4052","exceed",99,105],["G1722","in",106,108],["G1391","glory",109,114]]},"3:10":{"text":"For even that which was made glorious had no glory in this respect, by reason of the glory that excelleth.","words":[["G1063","For",0,3],["G2532","even",4,8],["G1392","that which was made glorious",9,37],["G3761","had no",38,44],["G1392","glory",45,50],["G1722","in",51,53],["G5129","this",54,58],["G3313","respect",59,66],["G1752","by reason",68,77],["G1391","of the glory",78,90],["G5235","that excelleth",91,105]]},"3:11":{"text":"For if that which is done away was glorious, much more that which remaineth is glorious.","words":[["G1063","For",0,3],["G1487","if",4,6],["G2673","that which is done away",7,30],["G1223","was glorious",31,43],["G1391","was glorious",31,43],["G4183","much",45,49],["G3123","more",50,54],["G3306","that which remaineth",55,75],["G1722","is glorious",76,87],["G1391","is glorious",76,87]]},"3:12":{"text":"Seeing then that we have such hope, we use great plainness of speech:","words":[["G3767","Seeing then",0,11],["G2192","that we have",12,24],["G5108","such",25,29],["G1680","hope",30,34],["G5530","we use",36,42],["G4183","great",43,48],["G3954","plainness of speech",49,68]]},"3:13":{"text":"And not as Moses, which put a vail over his face, that the children of Israel could not stedfastly look to the end of that which is abolished:","words":[["G2532","And",0,3],["G3756","not",4,7],["G2509","as",8,10],["G3475","Moses",11,16],["G5087","which put",18,27],["G2571","a vail",28,34],["G1909","over",35,39],["G1438","his",40,43],["G4383","face",44,48],["G4314","that",50,54],["G5207","the children",55,67],["G2474","of Israel",68,77],["G0816","could",78,83],["G3361","not",84,87],["G0816","stedfastly look",88,103],["G1519","to",104,106],["G5056","the end",107,114],["G2673","of that which is abolished",115,141]]},"3:14":{"text":"But their minds were blinded: for until this day remaineth the same vail untaken away in the reading of the old testament; which vail is done away in Christ.","words":[["G0235","But",0,3],["G0846","their",4,9],["G3540","minds",10,15],["G4456","were blinded",16,28],["G1063","for",30,33],["G0891","until",34,39],["G4594","this day",40,48],["G3306","remaineth",49,58],["G0846","the same",59,67],["G2571","vail",68,72],["G3361","untaken",73,80],["G0343","away",81,85],["G1909","in",86,88],["G0320","the reading",89,100],["G3820","of the old",101,111],["G1242","testament",112,121],["G3748","which",123,128],["G2673","vail is done away",129,146],["G1722","in",147,149],["G5547","Christ",150,156]]},"3:15":{"text":"But even unto this day, when Moses is read, the vail is upon their heart.","words":[["G0235","But",0,3],["G2193","even",4,8],["G4594","unto this day",9,22],["G2259","when",24,28],["G3475","Moses",29,34],["G0314","is read",35,42],["G2571","the vail",44,52],["G2749","is upon",53,60],["G1909","is upon",53,60],["G0846","their",61,66],["G2588","heart",67,72]]},"3:16":{"text":"Nevertheless when it shall turn to the Lord, the vail shall be taken away.","words":[["G1161","Nevertheless",0,12],["G2259","when",13,17],["G0302","it",18,20],["G1994","shall turn",21,31],["G4314","to",32,34],["G2962","the Lord",35,43],["G2571","the vail",45,53],["G4014","shall be taken away",54,73]]},"3:17":{"text":"Now the Lord is that Spirit: and where the Spirit of the Lord is, there is liberty.","words":[["G1161","Now",0,3],["G2962","the Lord",4,12],["G2076","is",13,15],["G4151","that Spirit",16,27],["G1161","and",29,32],["G3757","where",33,38],["G4151","the Spirit",39,49],["G2962","of the Lord",50,61],["G1563","is, there",62,71],["G1657","is liberty",72,82]]},"3:18":{"text":"But we all, with open face beholding as in a glass the glory of the Lord, are changed into the same image from glory to glory, even as by the Spirit of the Lord.","words":[["G1161","But",0,3],["G2249","we",4,6],["G3956","all",7,10],["G0343","with open",12,21],["G4383","face",22,26],["G2734","beholding as in a glass",27,50],["G1391","the glory",51,60],["G2962","of the Lord",61,72],["G3339","are changed",74,85],["G0846","into the same",86,99],["G1504","image",100,105],["G0575","from",106,110],["G1391","glory",111,116],["G1519","to",117,119],["G1391","glory",120,125],["G2509","even as",127,134],["G0575","by",135,137],["G4151","the Spirit",138,148],["G2962","of the Lord",149,160]]},"4:1":{"text":"Therefore seeing we have this ministry, as we have received mercy, we faint not;","words":[["G1223","Therefore seeing",0,16],["G5124","Therefore seeing",0,16],["G2192","we have",17,24],["G5026","this",25,29],["G1248","ministry",30,38],["G2531","as",40,42],["G1653","we have received mercy",43,65],["G1573","we faint",67,75],["G3756","not",76,79]]},"4:2":{"text":"But have renounced the hidden things of dishonesty, not walking in craftiness, nor handling the word of God deceitfully; but by manifestation of the truth commending ourselves to every man's conscience in the sight of God.","words":[["G0235","But",0,3],["G0550","have renounced",4,18],["G2927","the hidden things",19,36],["G0152","of dishonesty",37,50],["G3361","not",52,55],["G4043","walking",56,63],["G1722","in",64,66],["G3834","craftiness",67,77],["G3366","nor",79,82],["G1389","handling",83,91],["G3056","the word",92,100],["G2316","of God",101,107],["G1389","deceitfully",108,119],["G0235","but",121,124],["G5321","by manifestation",125,141],["G0225","of the truth",142,154],["G4921","commending",155,165],["G1438","ourselves",166,175],["G4314","to",176,178],["G3956","every",179,184],["G0444","man's",185,190],["G4893","conscience",191,201],["G1799","in the sight",202,214],["G2316","of God",215,221]]},"4:3":{"text":"But if our gospel be hid, it is hid to them that are lost:","words":[["G1161","But",0,3],["G1499","if",4,6],["G2257","our",7,10],["G2098","gospel",11,17],["G2076","be",18,20],["G2572","hid",21,24],["G2076","it is",26,31],["G2572","hid",32,35],["G1722","to",36,38],["G0622","them that are lost",39,57]]},"4:4":{"text":"In whom the god of this world hath blinded the minds of them which believe not, lest the light of the glorious gospel of Christ, who is the image of God, should shine unto them.","words":[["G1722","In",0,2],["G3739","whom",3,7],["G2316","the god",8,15],["G5127","of this",16,23],["G0165","world",24,29],["G5186","hath blinded",30,42],["G3540","the minds",43,52],["G0571","of them which believe not",53,78],["G1519","lest",80,84],["G3361","lest",80,84],["G5462","the light",85,94],["G1391","of the glorious",95,110],["G2098","gospel",111,117],["G5547","of Christ",118,127],["G3739","who",129,132],["G2076","is",133,135],["G1504","the image",136,145],["G2316","of God",146,152],["G0826","should shine",154,166],["G0846","unto them",167,176]]},"4:5":{"text":"For we preach not ourselves, but Christ Jesus the Lord; and ourselves your servants for Jesus' sake.","words":[["G1063","For",0,3],["G2784","we preach",4,13],["G3756","not",14,17],["G1438","ourselves",18,27],["G0235","but",29,32],["G5547","Christ",33,39],["G2424","Jesus",40,45],["G2962","the Lord",46,54],["G1161","and",56,59],["G1438","ourselves",60,69],["G5216","your",70,74],["G1401","servants",75,83],["G1223","for",84,87],["G2424","Jesus'",88,94],["G1223","sake",95,99]]},"4:6":{"text":"For God, who commanded the light to shine out of darkness, hath shined in our hearts, to give the light of the knowledge of the glory of God in the face of Jesus Christ.","words":[["G3754","For",0,3],["G2316","God",4,7],["G3588","who",9,12],["G2036","commanded",13,22],["G5457","the light",23,32],["G2989","to shine",33,41],["G1537","out of",42,48],["G4655","darkness",49,57],["G3739","",-1,-1],["G2989","hath shined",59,70],["G1722","in",71,73],["G2257","our",74,77],["G2588","hearts",78,84],["G4314","to",86,88],["G5462","give the light",89,103],["G1108","of the knowledge",104,120],["G1391","of the glory",121,133],["G2316","of God",134,140],["G1722","in",141,143],["G4383","the face",144,152],["G2424","of Jesus",153,161],["G5547","Christ",162,168]]},"4:7":{"text":"But we have this treasure in earthen vessels, that the excellency of the power may be of God, and not of us.","words":[["G1161","But",0,3],["G2192","we have",4,11],["G5126","this",12,16],["G2344","treasure",17,25],["G1722","in",26,28],["G3749","earthen",29,36],["G4632","vessels",37,44],["G2443","that",46,50],["G5236","the excellency",51,65],["G1411","of the power",66,78],["G5600","may be",79,85],["G2316","of God",86,92],["G2532","and",94,97],["G3361","not",98,101],["G1537","of",102,104],["G2257","us",105,107]]},"4:8":{"text":"We are troubled on every side, yet not distressed; we are perplexed, but not in despair;","words":[["G2346","We are troubled",0,15],["G1722","on",16,18],["G3956","every side",19,29],["G0235","yet",31,34],["G3756","not",35,38],["G4729","distressed",39,49],["G0639","we are perplexed",51,67],["G0235","but",69,72],["G3756","not",73,76],["G1820","in despair",77,87]]},"4:9":{"text":"Persecuted, but not forsaken; cast down, but not destroyed;","words":[["G1377","Persecuted",0,10],["G0235","but",12,15],["G3756","not",16,19],["G1459","forsaken",20,28],["G2598","cast down",30,39],["G0235","but",41,44],["G3756","not",45,48],["G0622","destroyed",49,58]]},"4:10":{"text":"Always bearing about in the body the dying of the Lord Jesus, that the life also of Jesus might be made manifest in our body.","words":[["G3842","Always",0,6],["G4064","bearing about",7,20],["G1722","in",21,23],["G4983","the body",24,32],["G3500","the dying",33,42],["G2962","of the Lord",43,54],["G2424","Jesus",55,60],["G2443","that",62,66],["G2222","the life",67,75],["G2532","also",76,80],["G2424","of Jesus",81,89],["G5319","might be made manifest",90,112],["G1722","in",113,115],["G2257","our",116,119],["G4983","body",120,124]]},"4:11":{"text":"For we which live are alway delivered unto death for Jesus' sake, that the life also of Jesus might be made manifest in our mortal flesh.","words":[["G2249","For we",0,6],["G3588","which",7,12],["G2198","live",13,17],["G3860","are",18,21],["G0104","alway",22,27],["G1063","alway",22,27],["G3860","delivered",28,37],["G1519","unto",38,42],["G2288","death",43,48],["G1223","for",49,52],["G2424","Jesus'",53,59],["G1223","sake",60,64],["G2443","that",66,70],["G2222","the life",71,79],["G2532","also",80,84],["G2424","of Jesus",85,93],["G5319","might be made manifest",94,116],["G1722","in",117,119],["G2257","our",120,123],["G2349","mortal",124,130],["G4561","flesh",131,136]]},"4:12":{"text":"So then death worketh in us, but life in you.","words":[["G5620","So",0,2],["G3303","then",3,7],["G2288","death",8,13],["G1754","worketh",14,21],["G1722","in",22,24],["G2254","us",25,27],["G1161","but",29,32],["G2222","life",33,37],["G1722","in",38,40],["G5213","you",41,44]]},"4:13":{"text":"We having the same spirit of faith, according as it is written, I believed, and therefore have I spoken; we also believe, and therefore speak;","words":[["G1161","",-1,-1],["G2192","We having",0,9],["G0846","the same",10,18],["G4151","spirit",19,25],["G4102","of faith",26,34],["G2596","according as",36,48],["G1125","it is written",49,62],["G4100","I believed",64,74],["G1352","and therefore",76,89],["G2980","have I spoken",90,103],["G2249","we",105,107],["G2532","also",108,112],["G4100","believe",113,120],["G2532","and",122,125],["G1352","therefore",126,135],["G2980","speak",136,141]]},"4:14":{"text":"Knowing that he which raised up the Lord Jesus shall raise up us also by Jesus, and shall present us with you.","words":[["G1492","Knowing",0,7],["G3754","that",8,12],["G1453","he which raised up",13,31],["G2962","the Lord",32,40],["G2424","Jesus",41,46],["G1453","shall raise up",47,61],["G2248","us",62,64],["G2532","also",65,69],["G1223","by",70,72],["G2424","Jesus",73,78],["G2532","and",80,83],["G3936","shall present",84,97],["G4862","us with",98,105],["G5213","you",106,109]]},"4:15":{"text":"For all things are for your sakes, that the abundant grace might through the thanksgiving of many redound to the glory of God.","words":[["G1063","For",0,3],["G3956","all things",4,14],["G1223","are for",15,22],["G5209","your",23,27],["G1223","sakes",28,33],["G2443","that",35,39],["G4121","the abundant",40,52],["G5485","grace",53,58],["G4052","might",59,64],["G1223","through",65,72],["G2169","the thanksgiving",73,89],["G4119","of many",90,97],["G4052","redound",98,105],["G1519","to",106,108],["G1391","the glory",109,118],["G2316","of God",119,125]]},"4:16":{"text":"For which cause we faint not; but though our outward man perish, yet the inward man is renewed day by day.","words":[["G1352","For which cause",0,15],["G1573","we faint",16,24],["G3756","not",25,28],["G0235","but",30,33],["G1499","though",34,40],["G2257","our",41,44],["G1854","outward",45,52],["G0444","man",53,56],["G1311","perish",57,63],["G0235","yet",65,68],["G2081","the inward",69,79],["G0341","man is renewed",80,94],["G2250","day",95,98],["G2532","by",99,101],["G2250","day",102,105]]},"4:17":{"text":"For our light affliction, which is but for a moment, worketh for us a far more exceeding and eternal weight of glory;","words":[["G1063","For",0,3],["G2257","our",4,7],["G1645","light",8,13],["G2347","affliction",14,24],["G3588","which",26,31],["G3910","is but for a moment",32,51],["G2716","worketh",53,60],["G2254","for us",61,67],["G2596","a far",68,73],["G5236","a far",68,73],["G1519","more exceeding",74,88],["G5236","more exceeding",74,88],["G0166","and eternal",89,100],["G0922","weight",101,107],["G1391","of glory",108,116]]},"4:18":{"text":"While we look not at the things which are seen, but at the things which are not seen: for the things which are seen are temporal; but the things which are not seen are eternal.","words":[["G4648","While",0,5],["G2257","we",6,8],["G4648","look",9,13],["G3361","not",14,17],["G4648","at",18,20],["G0991","the things which are seen",21,46],["G0235","but",48,51],["G0991","at the things which are",52,75],["G3361","not",76,79],["G0991","seen",80,84],["G1063","for",86,89],["G0991","the things which are seen",90,115],["G4340","are temporal",116,128],["G1161","but",130,133],["G0991","the things which are",134,154],["G3361","not",155,158],["G0991","seen",159,163],["G0166","are eternal",164,175]]},"5:1":{"text":"For we know that if our earthly house of this tabernacle were dissolved, we have a building of God, an house not made with hands, eternal in the heavens.","words":[["G1063","For",0,3],["G1492","we know",4,11],["G3754","that",12,16],["G1437","if",17,19],["G2257","our",20,23],["G1919","earthly",24,31],["G3614","house",32,37],["G4636","of this tabernacle",38,56],["G2647","were dissolved",57,71],["G2192","we have",73,80],["G3619","a building",81,91],["G1537","of",92,94],["G2316","God",95,98],["G3614","an house",100,108],["G0886","not made with hands",109,128],["G0166","eternal",130,137],["G1722","in",138,140],["G3772","the heavens",141,152]]},"5:2":{"text":"For in this we groan, earnestly desiring to be clothed upon with our house which is from heaven:","words":[["G2532","For",0,3],["G1063","For",0,3],["G1722","in",4,6],["G5129","this",7,11],["G4727","we groan",12,20],["G1971","earnestly desiring",22,40],["G1902","to be clothed upon",41,59],["G2257","with our",60,68],["G3613","house",69,74],["G3588","which",75,80],["G1537","is from",81,88],["G3772","heaven",89,95]]},"5:3":{"text":"If so be that being clothed we shall not be found naked.","words":[["G1489","If",0,2],["G2532","so",3,5],["G1746","be that being clothed",6,27],["G2147","we shall",28,36],["G3756","not",37,40],["G2147","be found",41,49],["G1131","naked",50,55]]},"5:4":{"text":"For we that are in this tabernacle do groan, being burdened: not for that we would be unclothed, but clothed upon, that mortality might be swallowed up of life.","words":[["G2532","For",0,3],["G1063","For",0,3],["G5607","we that are",4,15],["G1722","in",16,18],["G4636","this tabernacle",19,34],["G4727","do groan",35,43],["G0916","being burdened",45,59],["G3756","not",61,64],["G1894","for that",65,73],["G2309","we would",74,82],["G1562","be unclothed",83,95],["G0235","but",97,100],["G1902","clothed upon",101,113],["G2443","that",115,119],["G2349","mortality",120,129],["G2666","might be swallowed up",130,151],["G5259","of",152,154],["G2222","life",155,159]]},"5:5":{"text":"Now he that hath wrought us for the selfsame thing is God, who also hath given unto us the earnest of the Spirit.","words":[["G1161","Now",0,3],["G2716","he that hath wrought",4,24],["G2248","us",25,27],["G1519","for",28,31],["G0846","the selfsame thing",32,50],["G5124","the selfsame thing",32,50],["G2316","is God",51,57],["G3588","who",59,62],["G2532","also",63,67],["G1325","hath given",68,78],["G2254","unto us",79,86],["G0728","the earnest",87,98],["G4151","of the Spirit",99,112]]},"5:6":{"text":"Therefore we are always confident, knowing that, whilst we are at home in the body, we are absent from the Lord:","words":[["G3767","Therefore",0,9],["G2532","Therefore",0,9],["G3842","we are always",10,23],["G2292","confident",24,33],["G1492","knowing",35,42],["G3754","that",43,47],["G1736","whilst we are at home",49,70],["G1722","in",71,73],["G4983","the body",74,82],["G1553","we are absent",84,97],["G0575","from",98,102],["G2962","the Lord",103,111]]},"5:7":{"text":"(For we walk by faith, not by sight:)","words":[["G1063","(For",0,4],["G4043","we walk",5,12],["G1223","by",13,15],["G4102","faith",16,21],["G3756","not",23,26],["G1223","by",27,29],["G1491","sight",30,35]]},"5:8":{"text":"We are confident, I say, and willing rather to be absent from the body, and to be present with the Lord.","words":[["G2292","We are confident",0,16],["G1161","I say, and",18,28],["G2532","I say, and",18,28],["G2106","willing",29,36],["G3123","rather",37,43],["G1553","to be absent",44,56],["G1537","from",57,61],["G4983","the body",62,70],["G2532","and",72,75],["G1736","to be present",76,89],["G4314","with",90,94],["G2962","the Lord",95,103]]},"5:9":{"text":"Wherefore we labour, that, whether present or absent, we may be accepted of him.","words":[["G1352","Wherefore",0,9],["G5389","we labour",10,19],["G2532","that",21,25],["G1535","whether",27,34],["G1736","present",35,42],["G1535","or",43,45],["G1553","absent",46,52],["G1511","we may be",54,63],["G2101","accepted",64,72],["G0846","of him",73,79]]},"5:10":{"text":"For we must all appear before the judgment seat of Christ; that every one may receive the things done in his body, according to that he hath done, whether it be good or bad.","words":[["G1063","For",0,3],["G2248","we",4,6],["G1163","must",7,11],["G3956","all",12,15],["G5319","appear",16,22],["G1715","before",23,29],["G0968","the judgment seat",30,47],["G5547","of Christ",48,57],["G2443","that",59,63],["G1538","every one",64,73],["G2865","may receive",74,85],["G1223","the things done in",86,104],["G4983","his body",105,113],["G4314","according",115,124],["G3739","to that",125,132],["G4238","he hath done",133,145],["G1535","whether",147,154],["G0018","it be good",155,165],["G1535","or",166,168],["G2556","bad",169,172]]},"5:11":{"text":"Knowing therefore the terror of the Lord, we persuade men; but we are made manifest unto God; and I trust also are made manifest in your consciences.","words":[["G1492","Knowing",0,7],["G3767","therefore",8,17],["G5401","the terror",18,28],["G2962","of the Lord",29,40],["G3982","we persuade",42,53],["G0444","men",54,57],["G1161","but",59,62],["G5319","we are made manifest",63,83],["G2316","unto God",84,92],["G1161","and",94,97],["G1679","I trust",98,105],["G2532","also",106,110],["G5319","are made manifest",111,128],["G1722","in",129,131],["G5216","your",132,136],["G4893","consciences",137,148]]},"5:12":{"text":"For we commend not ourselves again unto you, but give you occasion to glory on our behalf, that ye may have somewhat to answer them which glory in appearance, and not in heart.","words":[["G1063","For",0,3],["G4921","we commend",4,14],["G3756","not",15,18],["G1438","ourselves",19,28],["G3825","again",29,34],["G5213","unto you",35,43],["G0235","but",45,48],["G1325","give",49,53],["G5213","you",54,57],["G0874","occasion",58,66],["G2745","to glory",67,75],["G5228","on",76,78],["G2257","our",79,82],["G5228","behalf",83,89],["G2443","that",91,95],["G2192","ye may have",96,107],["G4314","somewhat to",108,119],["G2744","answer them which glory",120,143],["G1722","in",144,146],["G4383","appearance",147,157],["G2532","and",159,162],["G3756","not",163,166],["G2588","in heart",167,175]]},"5:13":{"text":"For whether we be beside ourselves, it is to God: or whether we be sober, it is for your cause.","words":[["G1063","For",0,3],["G1535","whether",4,11],["G1839","we be beside ourselves",12,34],["G2316","it is to God",36,48],["G1535","or whether",50,60],["G4993","we be sober",61,72],["G5213","it is for your cause",74,94]]},"5:14":{"text":"For the love of Christ constraineth us; because we thus judge, that if one died for all, then were all dead:","words":[["G1063","For",0,3],["G0026","the love",4,12],["G5547","of Christ",13,22],["G4912","constraineth",23,35],["G2248","us",36,38],["G5124","because we thus",40,55],["G2919","judge",56,61],["G3754","that",63,67],["G1487","if",68,70],["G1520","one",71,74],["G0599","died",75,79],["G5228","for",80,83],["G3956","all",84,87],["G0686","then",89,93],["G0599","were",94,98],["G3956","all",99,102],["G0599","dead",103,107]]},"5:15":{"text":"And that he died for all, that they which live should not henceforth live unto themselves, but unto him which died for them, and rose again.","words":[["G2532","And",0,3],["G0599","that he died",4,16],["G5228","for",17,20],["G3956","all",21,24],["G2443","that",26,30],["G2198","they which live",31,46],["G2198","should",47,53],["G3371","not henceforth",54,68],["G2198","live",69,73],["G1438","unto themselves",74,89],["G0235","but",91,94],["G0599","unto him which died",95,114],["G5228","for",115,118],["G0846","them",119,123],["G2532","and",125,128],["G1453","rose again",129,139]]},"5:16":{"text":"Wherefore henceforth know we no man after the flesh: yea, though we have known Christ after the flesh, yet now henceforth know we him no more.","words":[["G5620","Wherefore",0,9],["G0575","henceforth",10,20],["G3568","henceforth",10,20],["G1492","know",21,25],["G2249","we",26,28],["G3762","no man",29,35],["G2596","after",36,41],["G4561","the flesh",42,51],["G1161","yea",53,56],["G1499","though",58,64],["G1097","we have known",65,78],["G5547","Christ",79,85],["G2596","after",86,91],["G4561","the flesh",92,101],["G0235","yet",103,106],["G3568","now",107,110],["G3765","henceforth",111,121],["G1097","know we",122,129],["G3765","him no more",130,141]]},"5:17":{"text":"Therefore if any man be in Christ, he is a new creature: old things are passed away; behold, all things are become new.","words":[["G5620","Therefore",0,9],["G1536","if any man",10,20],["G1722","be in",21,26],["G5547","Christ",27,33],["G2537","he is a new",35,46],["G2937","creature",47,55],["G0744","old things",57,67],["G3928","are passed away",68,83],["G2400","behold",85,91],["G3956","all things",93,103],["G1096","are become",104,114],["G2537","new",115,118]]},"5:18":{"text":"And all things are of God, who hath reconciled us to himself by Jesus Christ, and hath given to us the ministry of reconciliation;","words":[["G1161","And",0,3],["G3956","all things",4,14],["G1537","are of",15,21],["G2316","God",22,25],["G3588","who",27,30],["G2644","hath reconciled",31,46],["G2248","us",47,49],["G1438","to himself",50,60],["G1223","by",61,63],["G2424","Jesus",64,69],["G5547","Christ",70,76],["G2532","and",78,81],["G1325","hath given",82,92],["G2254","to us",93,98],["G1248","the ministry",99,111],["G2643","of reconciliation",112,129]]},"5:19":{"text":"To wit, that God was in Christ, reconciling the world unto himself, not imputing their trespasses unto them; and hath committed unto us the word of reconciliation.","words":[["G5613","To wit",0,6],["G3754","that",8,12],["G2316","God",13,16],["G2258","was",17,20],["G1722","in",21,23],["G5547","Christ",24,30],["G2644","reconciling",32,43],["G2889","the world",44,53],["G1438","unto himself",54,66],["G3361","not",68,71],["G3049","imputing",72,80],["G0846","their",81,86],["G3900","trespasses",87,97],["G0846","unto them",98,107],["G2532","and",109,112],["G5087","hath committed",113,127],["G1722","unto",128,132],["G2254","us",133,135],["G3056","the word",136,144],["G2643","of reconciliation",145,162]]},"5:20":{"text":"Now then we are ambassadors for Christ, as though God did beseech you by us: we pray you in Christ's stead, be ye reconciled to God.","words":[["G3767","Now then",0,8],["G4243","we are ambassadors",9,27],["G5228","for",28,31],["G5547","Christ",32,38],["G5613","as though",40,49],["G2316","God",50,53],["G3870","did beseech",54,65],["G1223","you by",66,72],["G2257","us",73,75],["G1189","we pray",77,84],["G5228","you in",85,91],["G5547","Christ's",92,100],["G5228","stead",101,106],["G2644","be ye reconciled",108,124],["G2316","to God",125,131]]},"5:21":{"text":"For he hath made him to be sin for us, who knew no sin; that we might be made the righteousness of God in him.","words":[["G1063","For",0,3],["G4160","he hath made",4,16],["G0266","him to be sin",17,30],["G5228","for",31,34],["G2257","us",35,37],["G3588","who",39,42],["G1097","knew",43,47],["G3361","no",48,50],["G0266","sin",51,54],["G2443","that",56,60],["G2249","we",61,63],["G1096","might be made",64,77],["G1343","the righteousness",78,95],["G2316","of God",96,102],["G1722","in",103,105],["G0846","him",106,109]]},"6:1":{"text":"We then, as workers together with him, beseech you also that ye receive not the grace of God in vain.","words":[["G3870","We",0,2],["G1161","then",3,7],["G4903","as workers together",9,28],["G3870","with him, beseech",29,46],["G2532","you also",47,55],["G5209","that ye",56,63],["G1209","receive",64,71],["G3361","not",72,75],["G5485","the grace",76,85],["G2316","of God",86,92],["G1519","in",93,95],["G2756","vain",96,100]]},"6:2":{"text":"(For he saith, I have heard thee in a time accepted, and in the day of salvation have I succoured thee: behold, now is the accepted time; behold, now is the day of salvation.)","words":[["G1063","(For",0,4],["G3004","he saith",5,13],["G1873","I have heard",15,27],["G4675","thee",28,32],["G2540","in a time",33,42],["G1184","accepted",43,51],["G2532","and",53,56],["G1722","in",57,59],["G2250","the day",60,67],["G4991","of salvation",68,80],["G0997","have I succoured",81,97],["G4671","thee",98,102],["G2400","behold",104,110],["G3568","now",112,115],["G2144","is the accepted",116,131],["G2540","time",132,136],["G2400","behold",138,144],["G3568","now",146,149],["G2250","is the day",150,160],["G4991","of salvation",161,173]]},"6:3":{"text":"Giving no offence in any thing, that the ministry be not blamed:","words":[["G1325","Giving",0,6],["G3367","no",7,9],["G4349","offence",10,17],["G1722","in",18,20],["G3367","any thing",21,30],["G3363","that",32,36],["G1248","the ministry",37,49],["G3469","be",50,52],["G3363","not",53,56],["G3469","blamed",57,63]]},"6:4":{"text":"But in all things approving ourselves as the ministers of God, in much patience, in afflictions, in necessities, in distresses,","words":[["G0235","But",0,3],["G1722","in",4,6],["G3956","all",7,10],["G4921","things approving",11,27],["G1438","ourselves",28,37],["G5613","as",38,40],["G1249","the ministers",41,54],["G2316","of God",55,61],["G1722","in",63,65],["G4183","much",66,70],["G5281","patience",71,79],["G1722","in",81,83],["G2347","afflictions",84,95],["G1722","in",97,99],["G0318","necessities",100,111],["G1722","in",113,115],["G4730","distresses",116,126]]},"6:5":{"text":"In stripes, in imprisonments, in tumults, in labours, in watchings, in fastings;","words":[["G1722","In",0,2],["G4127","stripes",3,10],["G1722","in",12,14],["G5438","imprisonments",15,28],["G1722","in",30,32],["G0181","tumults",33,40],["G1722","in",42,44],["G2873","labours",45,52],["G1722","in",54,56],["G0070","watchings",57,66],["G1722","in",68,70],["G3521","fastings",71,79]]},"6:6":{"text":"By pureness, by knowledge, by longsuffering, by kindness, by the Holy Ghost, by love unfeigned,","words":[["G1722","By",0,2],["G0054","pureness",3,11],["G1722","by",13,15],["G1108","knowledge",16,25],["G1722","by",27,29],["G3115","longsuffering",30,43],["G1722","by",45,47],["G5544","kindness",48,56],["G1722","by",58,60],["G0040","the Holy",61,69],["G4151","Ghost",70,75],["G1722","by",77,79],["G0026","love",80,84],["G0505","unfeigned",85,94]]},"6:7":{"text":"By the word of truth, by the power of God, by the armour of righteousness on the right hand and on the left,","words":[["G1722","By",0,2],["G3056","the word",3,11],["G0225","of truth",12,20],["G1722","by",22,24],["G1411","the power",25,34],["G2316","of God",35,41],["G1223","by",43,45],["G3696","the armour",46,56],["G1343","of righteousness",57,73],["G1188","on the right hand",74,91],["G2532","and",92,95],["G0710","on the left",96,107]]},"6:8":{"text":"By honour and dishonour, by evil report and good report: as deceivers, and yet true;","words":[["G1223","By",0,2],["G1391","honour",3,9],["G2532","and",10,13],["G0819","dishonour",14,23],["G1223","by",25,27],["G1426","evil report",28,39],["G2532","and",40,43],["G2162","good report",44,55],["G5613","as",57,59],["G4108","deceivers",60,69],["G2532","and",71,74],["G0227","yet true",75,83]]},"6:9":{"text":"As unknown, and yet well known; as dying, and, behold, we live; as chastened, and not killed;","words":[["G5613","As",0,2],["G0050","unknown",3,10],["G2532","and",12,15],["G1921","yet well known",16,30],["G5613","as",32,34],["G0599","dying",35,40],["G2532","and",42,45],["G2400","behold",47,53],["G2198","we live",55,62],["G5613","as",64,66],["G3811","chastened",67,76],["G2532","and",78,81],["G3361","not",82,85],["G2289","killed",86,92]]},"6:10":{"text":"As sorrowful, yet alway rejoicing; as poor, yet making many rich; as having nothing, and yet possessing all things.","words":[["G5613","As",0,2],["G3076","sorrowful",3,12],["G1161","yet",14,17],["G0104","alway",18,23],["G5463","rejoicing",24,33],["G5613","as",35,37],["G4434","poor",38,42],["G1161","yet",44,47],["G4148","making",48,54],["G4183","many",55,59],["G4148","rich",60,64],["G5613","as",66,68],["G2192","having",69,75],["G3367","nothing",76,83],["G2532","and",85,88],["G2722","yet possessing",89,103],["G3956","all things",104,114]]},"6:11":{"text":"O ye Corinthians, our mouth is open unto you, our heart is enlarged.","words":[["G2881","O ye Corinthians",0,16],["G2257","our",18,21],["G4750","mouth",22,27],["G0455","is open",28,35],["G4314","unto",36,40],["G5209","you",41,44],["G2257","our",46,49],["G2588","heart",50,55],["G4115","is enlarged",56,67]]},"6:12":{"text":"Ye are not straitened in us, but ye are straitened in your own bowels.","words":[["G4729","Ye are",0,6],["G3756","not",7,10],["G4729","straitened",11,21],["G1722","in",22,24],["G2254","us",25,27],["G1161","but",29,32],["G4729","ye are straitened",33,50],["G1722","in",51,53],["G5216","your own",54,62],["G4698","bowels",63,69]]},"6:13":{"text":"Now for a recompence in the same, (I speak as unto my children,) be ye also enlarged.","words":[["G1161","Now",0,3],["G0489","for a recompence",4,20],["G0846","in the same",21,32],["G3004","(I speak",34,42],["G5613","as",43,45],["G5043","unto my children",46,62],["G4115",") be",63,67],["G5210","ye",68,70],["G2532","also",71,75],["G4115","enlarged",76,84]]},"6:14":{"text":"Be ye not unequally yoked together with unbelievers: for what fellowship hath righteousness with unrighteousness? and what communion hath light with darkness?","words":[["G1096","Be ye",0,5],["G3361","not",6,9],["G2086","unequally yoked together",10,34],["G0571","with unbelievers",35,51],["G1063","for",53,56],["G5101","what",57,61],["G3352","fellowship",62,72],["G1343","hath righteousness",73,91],["G2532","with",92,96],["G0458","unrighteousness",97,112],["G1161","and",114,117],["G5101","what",118,122],["G2842","communion",123,132],["G5457","hath light",133,143],["G4314","with",144,148],["G4655","darkness",149,157]]},"6:15":{"text":"And what concord hath Christ with Belial? or what part hath he that believeth with an infidel?","words":[["G1161","And",0,3],["G5101","what",4,8],["G4857","concord",9,16],["G5547","hath Christ",17,28],["G4314","with",29,33],["G0955","Belial",34,40],["G2228","or",42,44],["G5101","what",45,49],["G3310","part",50,54],["G4103","hath he that believeth",55,77],["G3326","with",78,82],["G0571","an infidel",83,93]]},"6:16":{"text":"And what agreement hath the temple of God with idols? for ye are the temple of the living God; as God hath said, I will dwell in them, and walk in them; and I will be their God, and they shall be my people.","words":[["G1161","And",0,3],["G5101","what",4,8],["G4783","agreement",9,18],["G3485","hath the temple",19,34],["G2316","of God",35,41],["G3326","with",42,46],["G1497","idols",47,52],["G1063","for",54,57],["G5210","ye",58,60],["G2075","are",61,64],["G3485","the temple",65,75],["G2198","of the living",76,89],["G2316","God",90,93],["G2531","as",95,97],["G2316","God",98,101],["G2036","hath said",102,111],["G3754","",-1,-1],["G1774","I will dwell",113,125],["G1722","in",126,128],["G0846","them",129,133],["G2532","and",135,138],["G1704","walk in",139,146],["G2532","them; and",147,156],["G2071","I will be",157,166],["G0846","their",167,172],["G2316","God",173,176],["G2532","and",178,181],["G0846","they",182,186],["G2071","shall be",187,195],["G3427","my",196,198],["G2992","people",199,205]]},"6:17":{"text":"Wherefore come out from among them, and be ye separate, saith the Lord, and touch not the unclean thing; and I will receive you,","words":[["G1352","Wherefore",0,9],["G1831","come out",10,18],["G1537","from",19,23],["G3319","among",24,29],["G0846","them",30,34],["G2532","and",36,39],["G0873","be ye separate",40,54],["G3004","saith",56,61],["G2962","the Lord",62,70],["G2532","and",72,75],["G0680","touch",76,81],["G3361","not",82,85],["G0169","the unclean",86,97],["G2504","thing; and",98,108],["G1523","I will receive",109,123],["G5209","you",124,127]]},"6:18":{"text":"And will be a Father unto you, and ye shall be my sons and daughters, saith the Lord Almighty.","words":[["G2532","And",0,3],["G2071","will be",4,11],["G1519","will be",4,11],["G3962","a Father",12,20],["G5213","unto you",21,29],["G2532","and",31,34],["G5210","ye",35,37],["G2071","shall be",38,46],["G3427","my",47,49],["G5207","sons",50,54],["G1519","sons",50,54],["G2532","and",55,58],["G2364","daughters",59,68],["G3004","saith",70,75],["G2962","the Lord",76,84],["G3841","Almighty",85,93]]},"7:1":{"text":"Having therefore these promises, dearly beloved, let us cleanse ourselves from all filthiness of the flesh and spirit, perfecting holiness in the fear of God.","words":[["G2192","Having",0,6],["G3767","therefore",7,16],["G5025","these",17,22],["G1860","promises",23,31],["G0027","dearly beloved",33,47],["G2511","let us cleanse",49,63],["G1438","ourselves",64,73],["G0575","from",74,78],["G3956","all",79,82],["G3436","filthiness",83,93],["G4561","of the flesh",94,106],["G2532","and",107,110],["G4151","spirit",111,117],["G2005","perfecting",119,129],["G0042","holiness",130,138],["G1722","in",139,141],["G5401","the fear",142,150],["G2316","of God",151,157]]},"7:2":{"text":"Receive us; we have wronged no man, we have corrupted no man, we have defrauded no man.","words":[["G5562","Receive",0,7],["G2248","us",8,10],["G0091","we have wronged",12,27],["G3762","no man",28,34],["G5351","we have corrupted",36,53],["G3762","no man",54,60],["G4122","we have defrauded",62,79],["G3762","no man",80,86]]},"7:3":{"text":"I speak not this to condemn you: for I have said before, that ye are in our hearts to die and live with you.","words":[["G3004","I speak",0,7],["G3756","not",8,11],["G4314","this to",12,19],["G2633","condemn",20,27],["G1063","you: for",28,36],["G4280","I have said before",37,55],["G3754","that",57,61],["G2075","ye are",62,68],["G1722","in",69,71],["G2257","our",72,75],["G2588","hearts",76,82],["G1519","to",83,85],["G4880","die",86,89],["G2532","and",90,93],["G4800","live with",94,103]]},"7:4":{"text":"Great is my boldness of speech toward you, great is my glorying of you: I am filled with comfort, I am exceeding joyful in all our tribulation.","words":[["G4183","Great",0,5],["G3427","is my",6,11],["G3954","boldness of speech",12,30],["G4314","toward",31,37],["G5209","you",38,41],["G4183","great",43,48],["G3427","is my",49,54],["G2746","glorying",55,63],["G5228","of",64,66],["G5216","you",67,70],["G4137","I am filled",72,83],["G3874","with comfort",84,96],["G5248","I am exceeding",98,112],["G5479","joyful",113,119],["G1909","in",120,122],["G3956","all",123,126],["G2257","our",127,130],["G2347","tribulation",131,142]]},"7:5":{"text":"For, when we were come into Macedonia, our flesh had no rest, but we were troubled on every side; without were fightings, within were fears.","words":[["G1063","For",0,3],["G2532","For",0,3],["G2257","when we",5,12],["G2064","were come",13,22],["G1519","into",23,27],["G3109","Macedonia",28,37],["G2257","our",39,42],["G4561","flesh",43,48],["G2192","had",49,52],["G3762","no",53,55],["G0425","rest",56,60],["G0235","but",62,65],["G2346","we were troubled",66,82],["G1722","on",83,85],["G3956","every side",86,96],["G1855","without",98,105],["G3163","were fightings",106,120],["G2081","within",122,128],["G5401","were fears",129,139]]},"7:6":{"text":"Nevertheless God, that comforteth those that are cast down, comforted us by the coming of Titus;","words":[["G0235","Nevertheless",0,12],["G2316","God",13,16],["G3870","that comforteth",18,33],["G5011","those that are cast down",34,58],["G3870","comforted",60,69],["G2248","us",70,72],["G1722","by",73,75],["G3952","the coming",76,86],["G5103","of Titus",87,95]]},"7:7":{"text":"And not by his coming only, but by the consolation wherewith he was comforted in you, when he told us your earnest desire, your mourning, your fervent mind toward me; so that I rejoiced the more.","words":[["G1161","And",0,3],["G3756","not",4,7],["G1722","by",8,10],["G0846","his",11,14],["G3952","coming",15,21],["G3440","only",22,26],["G0235","but",28,31],["G2532","but",28,31],["G1722","by",32,34],["G3874","the consolation",35,50],["G3739","wherewith",51,60],["G3870","he was comforted",61,77],["G1909","in",78,80],["G5213","you",81,84],["G0312","when he told",86,98],["G2254","us",99,101],["G5216","your",102,106],["G1972","earnest desire",107,121],["G5216","your",123,127],["G3602","mourning",128,136],["G5216","your",138,142],["G2205","fervent mind",143,155],["G5228","toward",156,162],["G1700","me",163,165],["G5620","so",167,169],["G3165","that I",170,176],["G5463","rejoiced",177,185],["G3123","the more",186,194]]},"7:8":{"text":"For though I made you sorry with a letter, I do not repent, though I did repent: for I perceive that the same epistle hath made you sorry, though it were but for a season.","words":[["G3754","For",0,3],["G1499","though",4,10],["G3076","I made",11,17],["G5209","you",18,21],["G3076","sorry",22,27],["G1722","with",28,32],["G1992","a letter",33,41],["G3338","I do",43,47],["G3756","not",48,51],["G3338","repent",52,58],["G1499","though",60,66],["G3338","I did repent",67,79],["G1063","for",81,84],["G0991","I perceive",85,95],["G3754","that",96,100],["G1565","the same",101,109],["G1992","epistle",110,117],["G3076","hath made",118,127],["G5209","you",128,131],["G3076","sorry",132,137],["G1499","though it were but",139,157],["G4314","for",158,161],["G5610","a season",162,170]]},"7:9":{"text":"Now I rejoice, not that ye were made sorry, but that ye sorrowed to repentance: for ye were made sorry after a godly manner, that ye might receive damage by us in nothing.","words":[["G3568","Now",0,3],["G5463","I rejoice",4,13],["G3756","not",15,18],["G3754","that",19,23],["G3076","ye were made sorry",24,42],["G0235","but",44,47],["G3754","that",48,52],["G3076","ye sorrowed",53,64],["G1519","to",65,67],["G3341","repentance",68,78],["G1063","for",80,83],["G3076","ye were made sorry",84,102],["G2596","after",103,108],["G2316","a godly manner",109,123],["G2443","that",125,129],["G2210","ye might receive damage",130,153],["G1537","by",154,156],["G2257","us",157,159],["G1722","in",160,162],["G3367","nothing",163,170]]},"7:10":{"text":"For godly sorrow worketh repentance to salvation not to be repented of: but the sorrow of the world worketh death.","words":[["G1063","For",0,3],["G2316","godly",4,9],["G2596","godly",4,9],["G3077","sorrow",10,16],["G2716","worketh",17,24],["G3341","repentance",25,35],["G1519","to",36,38],["G4991","salvation",39,48],["G0278","not to be repented of",49,70],["G1161","but",72,75],["G3077","the sorrow",76,86],["G2889","of the world",87,99],["G2716","worketh",100,107],["G2288","death",108,113]]},"7:11":{"text":"For behold this selfsame thing, that ye sorrowed after a godly sort, what carefulness it wrought in you, yea, what clearing of yourselves, yea, what indignation, yea, what fear, yea, what vehement desire, yea, what zeal, yea, what revenge! In all things ye have approved yourselves to be clear in this matter.","words":[["G1063","For",0,3],["G2400","behold",4,10],["G5124","this",11,15],["G0846","selfsame thing",16,30],["G5209","that",32,36],["G3076","ye sorrowed",37,48],["G2596","after",49,54],["G2316","a godly sort",55,67],["G4214","what",69,73],["G4710","carefulness",74,85],["G2716","it wrought",86,96],["G5213","in you",97,103],["G0235","yea",105,108],["G0627","what clearing of yourselves",110,137],["G0235","yea",139,142],["G0024","what indignation",144,160],["G0235","yea",162,165],["G5401","what fear",167,176],["G0235","yea",178,181],["G1972","what vehement desire",183,203],["G0235","yea",205,208],["G2205","what zeal",210,219],["G0235","yea",221,224],["G1557","what revenge",226,238],["G1722","In",240,242],["G3956","all",243,246],["G4921","things ye have approved",247,270],["G1438","yourselves",271,281],["G1511","to be",282,287],["G0053","clear",288,293],["G1722","in",294,296],["G4229","this matter",297,308]]},"7:12":{"text":"Wherefore, though I wrote unto you, I did it not for his cause that had done the wrong, nor for his cause that suffered wrong, but that our care for you in the sight of God might appear unto you.","words":[["G0686","Wherefore",0,9],["G1499","though",11,17],["G1125","I wrote",18,25],["G5213","unto you",26,34],["G3756","I did it not",36,48],["G1752","for his cause",49,62],["G0091","that had done the wrong",63,86],["G3761","nor",88,91],["G1752","for his cause",92,105],["G0091","that suffered wrong",106,125],["G0235","but",127,130],["G1752","that",131,135],["G2257","our",136,139],["G4710","care",140,144],["G5228","for",145,148],["G5216","you",149,152],["G1799","in the sight",153,165],["G2316","of God",166,172],["G5319","might appear",173,185],["G4314","unto",186,190],["G5209","you",191,194]]},"7:13":{"text":"Therefore we were comforted in your comfort: yea, and exceedingly the more joyed we for the joy of Titus, because his spirit was refreshed by you all.","words":[["G1223","Therefore",0,9],["G5124","Therefore",0,9],["G3870","we were comforted",10,27],["G1909","in",28,30],["G5216","your",31,35],["G3874","comfort",36,43],["G1161","yea, and",45,53],["G4056","exceedingly",54,65],["G3123","the more",66,74],["G5463","joyed we",75,83],["G1909","for",84,87],["G5479","the joy",88,95],["G5103","of Titus",96,104],["G3754","because",106,113],["G0846","his",114,117],["G4151","spirit",118,124],["G0373","was refreshed",125,138],["G0575","by",139,141],["G5216","you",142,145],["G3956","all",146,149]]},"7:14":{"text":"For if I have boasted any thing to him of you, I am not ashamed; but as we spake all things to you in truth, even so our boasting, which I made before Titus, is found a truth.","words":[["G3754","For",0,3],["G2744","if I have boasted",4,21],["G1536","any thing",22,31],["G0846","to him",32,38],["G5228","of",39,41],["G5216","you",42,45],["G2617","I am",47,51],["G3756","not",52,55],["G2617","ashamed",56,63],["G0235","but",65,68],["G5613","as",69,71],["G2980","we spake",72,80],["G3956","all things",81,91],["G5213","to you",92,98],["G1722","in",99,101],["G0225","truth",102,107],["G2532","even",109,113],["G3779","so",114,116],["G2257","our",117,120],["G2746","boasting",121,129],["G3588","which",131,136],["G1909","I made before",137,150],["G5103","Titus",151,156],["G1096","is found",158,166],["G0225","a truth",167,174]]},"7:15":{"text":"And his inward affection is more abundant toward you, whilst he remembereth the obedience of you all, how with fear and trembling ye received him.","words":[["G2532","And",0,3],["G0846","his",4,7],["G4698","inward affection",8,24],["G2076","is",25,27],["G4056","more abundant",28,41],["G1519","toward",42,48],["G5209","you",49,52],["G0363","whilst he remembereth",54,75],["G5218","the obedience",76,89],["G5216","of you",90,96],["G3956","all",97,100],["G5613","how",102,105],["G3326","with",106,110],["G5401","fear",111,115],["G2532","and",116,119],["G5156","trembling",120,129],["G1209","ye received",130,141],["G0846","him",142,145]]},"7:16":{"text":"I rejoice therefore that I have confidence in you in all things.","words":[["G5463","I rejoice",0,9],["G3754","therefore that",10,24],["G2292","I have confidence",25,42],["G1722","in",43,45],["G5213","you",46,49],["G1722","in",50,52],["G3956","all",53,56]]},"8:1":{"text":"Moreover, brethren, we do you to wit of the grace of God bestowed on the churches of Macedonia;","words":[["G1161","Moreover",0,8],["G0080","brethren",10,18],["G1107","we do",20,25],["G5213","you",26,29],["G1107","to wit",30,36],["G5485","of the grace",37,49],["G2316","of God",50,56],["G1325","bestowed",57,65],["G1722","on",66,68],["G1577","the churches",69,81],["G3109","of Macedonia",82,94]]},"8:2":{"text":"How that in a great trial of affliction the abundance of their joy and their deep poverty abounded unto the riches of their liberality.","words":[["G3754","How that",0,8],["G1722","in",9,11],["G4183","a great",12,19],["G1382","trial",20,25],["G2347","of affliction",26,39],["G4050","the abundance",40,53],["G0846","of their",54,62],["G5479","joy",63,66],["G2532","and",67,70],["G0846","their",71,76],["G0899","deep",77,81],["G2596","poverty",82,89],["G4432","poverty",82,89],["G4052","abounded",90,98],["G1519","unto",99,103],["G4149","the riches",104,114],["G0846","of their",115,123],["G0572","liberality",124,134]]},"8:3":{"text":"For to their power, I bear record, yea, and beyond their power they were willing of themselves;","words":[["G3754","For",0,3],["G2596","to",4,6],["G1411","their power",7,18],["G3140","I bear record",20,33],["G2532","yea, and",35,43],["G5228","beyond",44,50],["G1411","their power",51,62],["G0830","they were willing of themselves",63,94]]},"8:4":{"text":"Praying us with much intreaty that we would receive the gift, and take upon us the fellowship of the ministering to the saints.","words":[["G1189","Praying",0,7],["G2257","us",8,10],["G3326","with",11,15],["G4183","much",16,20],["G3874","intreaty",21,29],["G2248","that we",30,37],["G1209","would receive",38,51],["G5485","the gift",52,60],["G2532","and",62,65],["G2842","take upon us the fellowship",66,93],["G1248","of the ministering",94,112],["G1519","to",113,115],["G0040","the saints",116,126]]},"8:5":{"text":"And this they did, not as we hoped, but first gave their own selves to the Lord, and unto us by the will of God.","words":[["G2532","And",0,3],["G3756","this they did, not",4,22],["G2531","as",23,25],["G1679","we hoped",26,34],["G0235","but",36,39],["G4412","first",40,45],["G1325","gave",46,50],["G1438","their own selves",51,67],["G2962","to the Lord",68,79],["G2532","and",81,84],["G2254","unto us",85,92],["G1223","by",93,95],["G2307","the will",96,104],["G2316","of God",105,111]]},"8:6":{"text":"Insomuch that we desired Titus, that as he had begun, so he would also finish in you the same grace also.","words":[["G1519","Insomuch",0,8],["G2248","that we",9,16],["G3870","desired",17,24],["G5103","Titus",25,30],["G2443","that",32,36],["G2531","as",37,39],["G4278","he had begun",40,52],["G3779","so",54,56],["G2005","he would",57,65],["G2532","also",66,70],["G2005","finish",71,77],["G1519","in",78,80],["G5209","you",81,84],["G5026","the same",85,93],["G5485","grace",94,99],["G2532","also",100,104]]},"8:7":{"text":"Therefore, as ye abound in every thing, in faith, and utterance, and knowledge, and in all diligence, and in your love to us, see that ye abound in this grace also.","words":[["G0235","Therefore",0,9],["G5618","as",11,13],["G4052","ye abound",14,23],["G1722","in",24,26],["G3956","every",27,32],["G4102","thing, in faith",33,48],["G2532","and",50,53],["G3056","utterance",54,63],["G2532","and",65,68],["G1108","knowledge",69,78],["G2532","and",80,83],["G3956","in all",84,90],["G4710","diligence",91,100],["G2532","and",102,105],["G5216","in your",106,113],["G0026","love",114,118],["G1537","love",114,118],["G1722","to",119,121],["G2254","us",122,124],["G2443","see that",126,134],["G4052","ye abound",135,144],["G1722","in",145,147],["G5026","this",148,152],["G5485","grace",153,158],["G2532","also",159,163]]},"8:8":{"text":"I speak not by commandment, but by occasion of the forwardness of others, and to prove the sincerity of your love.","words":[["G3004","I speak",0,7],["G3756","not",8,11],["G2596","by",12,14],["G2003","commandment",15,26],["G0235","but",28,31],["G1223","by occasion",32,43],["G4710","of the forwardness",44,62],["G2087","of others",63,72],["G2532","and",74,77],["G1381","to prove",78,86],["G1103","the sincerity",87,100],["G5212","of your",101,108],["G0026","love",109,113]]},"8:9":{"text":"For ye know the grace of our Lord Jesus Christ, that, though he was rich, yet for your sakes he became poor, that ye through his poverty might be rich.","words":[["G1063","For",0,3],["G1097","ye know",4,11],["G5485","the grace",12,21],["G2257","of our",22,28],["G2962","Lord",29,33],["G2424","Jesus",34,39],["G5547","Christ",40,46],["G3754","that",48,52],["G5607","though he was",54,67],["G4145","rich",68,72],["G1223","yet for",74,81],["G5209","your",82,86],["G1223","sakes",87,92],["G4433","he became poor",93,107],["G2443","that",109,113],["G5210","ye",114,116],["G1565","through his",117,128],["G4432","poverty",129,136],["G4147","might be rich",137,150]]},"8:10":{"text":"And herein I give my advice: for this is expedient for you, who have begun before, not only to do, but also to be forward a year ago.","words":[["G2532","And",0,3],["G1722","herein",4,10],["G5129","herein",4,10],["G1325","I give",11,17],["G1106","my advice",18,27],["G1063","for",29,32],["G5124","this",33,37],["G4851","is expedient",38,50],["G5213","for you",51,58],["G3748","who",60,63],["G4278","have begun before",64,81],["G3756","not",83,86],["G3440","only",87,91],["G4160","to do",92,97],["G0235","but",99,102],["G2532","also",103,107],["G2309","to be forward",108,121],["G4070","a year",122,128],["G0575","ago",129,132]]},"8:11":{"text":"Now therefore perform the doing of it; that as there was a readiness to will, so there may be a performance also out of that which ye have.","words":[["G3570","Now",0,3],["G1161","Now",0,3],["G2532","therefore",4,13],["G2005","perform",14,21],["G4160","the doing",22,31],["G3704","of it; that",32,43],["G2509","as",44,46],["G4288","there was a readiness",47,68],["G2309","to will",69,76],["G3779","so",78,80],["G2005","there may be a performance",81,107],["G2532","also",108,112],["G1537","out of",113,119],["G2192","that which ye have",120,138]]},"8:12":{"text":"For if there be first a willing mind, it is accepted according to that a man hath, and not according to that he hath not.","words":[["G1063","For",0,3],["G1487","if there",4,12],["G4295","be first",13,21],["G4288","a willing mind",22,36],["G2144","it is accepted",38,52],["G2526","according to",53,65],["G1437","that",66,70],["G5100","a man",71,76],["G2192","hath",77,81],["G3756","and not",83,90],["G2526","according to that",91,108],["G2192","he hath",109,116],["G3756","not",117,120]]},"8:13":{"text":"For I mean not that other men be eased, and ye burdened:","words":[["G1063","For",0,3],["G3756","I mean not",4,14],["G2443","that",15,19],["G0243","other men",20,29],["G0425","be eased",30,38],["G1161","and",40,43],["G5213","ye",44,46],["G2347","burdened",47,55]]},"8:14":{"text":"But by an equality, that now at this time your abundance may be a supply for their want, that their abundance also may be a supply for your want: that there may be equality:","words":[["G0235","But",0,3],["G1537","by",4,6],["G2471","an equality",7,18],["G3568","that now",20,28],["G1722","at",29,31],["G2540","this time",32,41],["G5216","your",42,46],["G4051","abundance",47,56],["G1519","may be a supply for",57,76],["G1565","their",77,82],["G5303","want",83,87],["G2443","that",89,93],["G1565","their",94,99],["G4051","abundance",100,109],["G2532","also",110,114],["G1096","may be",115,121],["G1519","a supply for",122,134],["G5216","your",135,139],["G5303","want",140,144],["G3704","that",146,150],["G1096","there may be",151,163],["G2471","equality",164,172]]},"8:15":{"text":"As it is written, He that had gathered much had nothing over; and he that had gathered little had no lack.","words":[["G2531","As",0,2],["G1125","it is written",3,16],["G3588","He that had gathered",18,38],["G4183","much",39,43],["G4121","had",44,47],["G3756","nothing",48,55],["G4121","over",56,60],["G2532","and",62,65],["G3588","he that had gathered",66,86],["G3641","little",87,93],["G1641","had",94,97],["G3756","no",98,100],["G1641","lack",101,105]]},"8:16":{"text":"But thanks be to God, which put the same earnest care into the heart of Titus for you.","words":[["G1161","But",0,3],["G5485","thanks",4,10],["G2316","be to God",11,20],["G3588","which",22,27],["G1325","put",28,31],["G0846","the same",32,40],["G4710","earnest care",41,53],["G1722","into",54,58],["G2588","the heart",59,68],["G5103","of Titus",69,77],["G5228","for",78,81],["G5216","you",82,85]]},"8:17":{"text":"For indeed he accepted the exhortation; but being more forward, of his own accord he went unto you.","words":[["G3754","For",0,3],["G3303","indeed",4,10],["G1209","he accepted",11,22],["G3874","the exhortation",23,38],["G1161","but",40,43],["G5225","being",44,49],["G4707","more forward",50,62],["G0830","of his own accord",64,81],["G1831","he went",82,89],["G4314","unto",90,94],["G5209","you",95,98]]},"8:18":{"text":"And we have sent with him the brother, whose praise is in the gospel throughout all the churches;","words":[["G1161","And",0,3],["G4842","we have sent",4,16],["G3326","with",17,21],["G0846","him",22,25],["G0080","the brother",26,37],["G3739","whose",39,44],["G1868","praise",45,51],["G1722","is in",52,57],["G2098","the gospel",58,68],["G1223","throughout",69,79],["G3956","all",80,83],["G1577","the churches",84,96]]},"8:19":{"text":"And not that only, but who was also chosen of the churches to travel with us with this grace, which is administered by us to the glory of the same Lord, and declaration of your ready mind:","words":[["G1161","And",0,3],["G3756","not",4,7],["G3440","that only",8,17],["G0235","but",19,22],["G5500","who was",23,30],["G2532","also",31,35],["G5500","chosen",36,42],["G5259","of",43,45],["G1577","the churches",46,58],["G4898","to travel",59,68],["G2257","with us",69,76],["G4862","with",77,81],["G5026","this",82,86],["G5485","grace",87,92],["G3588","which",94,99],["G1247","is administered",100,115],["G5259","by",116,118],["G2257","us",119,121],["G4314","to",122,124],["G1391","the glory",125,134],["G0846","of the same",135,146],["G2962","Lord",147,151],["G2532","and",153,156],["G5216","declaration of your",157,176],["G4288","ready mind",177,187]]},"8:20":{"text":"Avoiding this, that no man should blame us in this abundance which is administered by us:","words":[["G4724","Avoiding",0,8],["G5124","this",9,13],["G3361","that no",15,22],["G5100","man",23,26],["G3469","should blame",27,39],["G2248","us",40,42],["G1722","in",43,45],["G5026","this",46,50],["G0100","abundance",51,60],["G3588","which",61,66],["G1247","is administered",67,82],["G5259","by",83,85],["G2257","us",86,88]]},"8:21":{"text":"Providing for honest things, not only in the sight of the Lord, but also in the sight of men.","words":[["G4306","Providing",0,9],["G2570","for honest things",10,27],["G3756","not",29,32],["G3440","only",33,37],["G1799","in the sight",38,50],["G2962","of the Lord",51,62],["G0235","but",64,67],["G2532","also",68,72],["G1799","in the sight",73,85],["G0444","of men",86,92]]},"8:22":{"text":"And we have sent with them our brother, whom we have oftentimes proved diligent in many things, but now much more diligent, upon the great confidence which I have in you.","words":[["G1161","And",0,3],["G4842","we have sent",4,16],["G0846","with them",17,26],["G2257","our",27,30],["G0080","brother",31,38],["G3739","whom",40,44],["G1381","we have",45,52],["G4178","oftentimes",53,63],["G1381","proved",64,70],["G5607","proved",64,70],["G4705","diligent",71,79],["G1722","in",80,82],["G4183","many things",83,94],["G1161","but",96,99],["G3570","now",100,103],["G4183","much",104,108],["G4707","more diligent",109,122],["G4183","upon the great",124,138],["G4006","confidence",139,149],["G3588","which",150,155],["G1519","I have in",156,165],["G5209","you",166,169]]},"8:23":{"text":"Whether any do enquire of Titus, he is my partner and fellowhelper concerning you: or our brethren be enquired of, they are the messengers of the churches, and the glory of Christ.","words":[["G1535","Whether",0,7],["G5228","any do enquire of",8,25],["G5103","Titus",26,31],["G1699","he is my",33,41],["G2844","partner",42,49],["G2532","and",50,53],["G4904","fellowhelper",54,66],["G1519","concerning",67,77],["G5209","you",78,81],["G1535","or",83,85],["G2257","our",86,89],["G0080","brethren",90,98],["G0652","be enquired of, they are the messengers",99,138],["G1577","of the churches",139,154],["G1391","and the glory",156,169],["G5547","of Christ",170,179]]},"8:24":{"text":"Wherefore shew ye to them, and before the churches, the proof of your love, and of our boasting on your behalf.","words":[["G3767","Wherefore",0,9],["G1731","shew ye",10,17],["G1519","to",18,20],["G0846","them",21,25],["G2532","and",27,30],["G1519","before",31,37],["G4383","before",31,37],["G1577","the churches",38,50],["G1732","the proof",52,61],["G5216","of your",62,69],["G0026","love",70,74],["G2532","and",76,79],["G2257","of our",80,86],["G2746","boasting",87,95],["G5228","on",96,98],["G5216","your",99,103],["G5228","behalf",104,110]]},"9:1":{"text":"For as touching the ministering to the saints, it is superfluous for me to write to you:","words":[["G1063","For",0,3],["G3303","as",4,6],["G4012","touching",7,15],["G1248","the ministering",16,31],["G1519","to",32,34],["G0040","the saints",35,45],["G2076","it is",47,52],["G4053","superfluous",53,64],["G3427","for me",65,71],["G1125","to write",72,80],["G5213","to you",81,87]]},"9:2":{"text":"For I know the forwardness of your mind, for which I boast of you to them of Macedonia, that Achaia was ready a year ago; and your zeal hath provoked very many.","words":[["G1063","For",0,3],["G1492","I know",4,10],["G4288","the forwardness of",11,29],["G5216","your",30,34],["G4288","mind",35,39],["G3739","for which",41,50],["G2744","I boast",51,58],["G5228","of",59,61],["G5216","you",62,65],["G3110","to them of Macedonia",66,86],["G3754","that",88,92],["G0882","Achaia",93,99],["G3903","was ready",100,109],["G4070","a year",110,116],["G0575","ago",117,120],["G2532","and",122,125],["G5216","your",126,130],["G2205","zeal",131,135],["G1537","zeal",131,135],["G2042","hath provoked",136,149],["G4119","very many",150,159]]},"9:3":{"text":"Yet have I sent the brethren, lest our boasting of you should be in vain in this behalf; that, as I said, ye may be ready:","words":[["G1161","Yet",0,3],["G3992","have I sent",4,15],["G0080","the brethren",16,28],["G3363","lest",30,34],["G2257","our",35,38],["G2745","boasting",39,47],["G5228","of",48,50],["G5216","you",51,54],["G2758","should be in vain",55,72],["G1722","in",73,75],["G5129","this",76,80],["G3313","behalf",81,87],["G2443","that",89,93],["G2531","as",95,97],["G3004","I said",98,104],["G5600","ye may be",106,115],["G3903","ready",116,121]]},"9:4":{"text":"Lest haply if they of Macedonia come with me, and find you unprepared, we (that we say not, ye) should be ashamed in this same confident boasting.","words":[["G3381","Lest",0,4],["G4458","haply",5,10],["G1437","if",11,13],["G3110","they of Macedonia",14,31],["G2064","come",32,36],["G4862","with",37,41],["G1698","me",42,44],["G2532","and",46,49],["G2147","find",50,54],["G5209","you",55,58],["G0532","unprepared",59,69],["G2249","we",71,73],["G3363","(that",74,79],["G3004","we say",80,86],["G3363","not",87,90],["G5210","ye",92,94],["G2617","should be ashamed",96,113],["G1722","in",114,116],["G5026","this same",117,126],["G5287","confident",127,136],["G2746","boasting",137,145]]},"9:5":{"text":"Therefore I thought it necessary to exhort the brethren, that they would go before unto you, and make up beforehand your bounty, whereof ye had notice before, that the same might be ready, as a matter of bounty, and not as of covetousness.","words":[["G3767","Therefore",0,9],["G2233","I thought",10,19],["G0316","it necessary",20,32],["G3870","to exhort",33,42],["G0080","the brethren",43,55],["G2443","that",57,61],["G4281","they would go before",62,82],["G1519","unto",83,87],["G5209","you",88,91],["G2532","and",93,96],["G4294","make up beforehand",97,115],["G5216","your",116,120],["G2129","bounty",121,127],["G4293","whereof ye had notice before",129,157],["G5026","that the same",159,172],["G1511","might be",173,181],["G2092","ready",182,187],["G3779","",-1,-1],["G5613","as",189,191],["G2129","a matter of bounty",192,210],["G2532","and",212,215],["G3361","not",216,219],["G5618","as",220,222],["G4124","of covetousness",223,238]]},"9:6":{"text":"But this I say, He which soweth sparingly shall reap also sparingly; and he which soweth bountifully shall reap also bountifully.","words":[["G1161","But",0,3],["G5124","this",4,8],["G4687","I say, He which soweth",9,31],["G5340","sparingly",32,41],["G2325","shall reap",42,52],["G2532","also",53,57],["G5340","sparingly",58,67],["G2532","and",69,72],["G4687","he which soweth",73,88],["G1909","bountifully",89,100],["G2129","bountifully",89,100],["G2325","shall reap",101,111],["G2532","also",112,116],["G1909","bountifully",117,128],["G2129","bountifully",117,128]]},"9:7":{"text":"Every man according as he purposeth in his heart, so let him give; not grudgingly, or of necessity: for God loveth a cheerful giver.","words":[["G1538","Every man",0,9],["G2531","according as",10,22],["G4255","he purposeth",23,35],["G2588","in his heart",36,48],["G3361","so let him give; not",50,70],["G1537","grudgingly",71,81],["G3077","grudgingly",71,81],["G2228","or",83,85],["G1537","of",86,88],["G0318","necessity",89,98],["G1063","for",100,103],["G2316","God",104,107],["G0025","loveth",108,114],["G2431","a cheerful",115,125],["G1395","giver",126,131]]},"9:8":{"text":"And God is able to make all grace abound toward you; that ye, always having all sufficiency in all things, may abound to every good work:","words":[["G1161","And",0,3],["G2316","God",4,7],["G1415","is able",8,15],["G4052","to make",16,23],["G3956","all",24,27],["G5485","grace",28,33],["G4052","abound",34,40],["G1519","toward",41,47],["G5209","you",48,51],["G2443","that",53,57],["G3842","ye, always",58,68],["G2192","having",69,75],["G3956","all",76,79],["G0841","sufficiency",80,91],["G1722","in",92,94],["G3956","all",95,98],["G4052","things, may abound",99,117],["G1519","to",118,120],["G3956","every",121,126],["G0018","good",127,131],["G2041","work",132,136]]},"9:9":{"text":"(As it is written, He hath dispersed abroad; he hath given to the poor: his righteousness remaineth for ever.","words":[["G2531","(As",0,3],["G1125","it is written",4,17],["G4650","He hath dispersed abroad",19,43],["G1325","he hath given",45,58],["G3993","to the poor",59,70],["G0846","his",72,75],["G1343","righteousness",76,89],["G3306","remaineth",90,99],["G1519","for",100,103],["G0165","ever",104,108]]},"9:10":{"text":"Now he that ministereth seed to the sower both minister bread for your food, and multiply your seed sown, and increase the fruits of your righteousness;)","words":[["G1161","Now",0,3],["G2023","he that ministereth",4,23],["G4690","seed",24,28],["G4687","to the sower",29,41],["G2532","both",42,46],["G5524","minister",47,55],["G0740","bread",56,61],["G1519","for",62,65],["G1035","your food",66,75],["G2532","and",77,80],["G4129","multiply",81,89],["G5216","your",90,94],["G4703","seed sown",95,104],["G2532","and",106,109],["G0837","increase",110,118],["G1081","the fruits",119,129],["G5216","of your",130,137],["G1343","righteousness",138,151]]},"9:11":{"text":"Being enriched in every thing to all bountifulness, which causeth through us thanksgiving to God.","words":[["G4148","Being enriched",0,14],["G1722","in",15,17],["G3956","every thing",18,29],["G1519","to",30,32],["G3956","all",33,36],["G0572","bountifulness",37,50],["G3748","which",52,57],["G2716","causeth",58,65],["G1223","through",66,73],["G2257","us",74,76],["G2169","thanksgiving",77,89],["G2316","to God",90,96]]},"9:12":{"text":"For the administration of this service not only supplieth the want of the saints, but is abundant also by many thanksgivings unto God;","words":[["G3754","For",0,3],["G1248","the administration",4,22],["G5026","of this",23,30],["G3009","service",31,38],["G3756","not",39,42],["G3440","only",43,47],["G2076","supplieth",48,57],["G4322","supplieth",48,57],["G5303","the want",58,66],["G0040","of the saints",67,80],["G0235","but",82,85],["G4052","is abundant",86,97],["G2532","also",98,102],["G1223","by",103,105],["G4183","many",106,110],["G2169","thanksgivings",111,124],["G2316","unto God",125,133]]},"9:13":{"text":"Whiles by the experiment of this ministration they glorify God for your professed subjection unto the gospel of Christ, and for your liberal distribution unto them, and unto all men;","words":[["G1223","Whiles by",0,9],["G1382","the experiment",10,24],["G5026","of this",25,32],["G1248","ministration",33,45],["G1392","they glorify",46,58],["G2316","God",59,62],["G1909","for",63,66],["G5216","your",67,71],["G3671","professed",72,81],["G5292","subjection",82,92],["G1519","unto",93,97],["G2098","the gospel",98,108],["G5547","of Christ",109,118],["G2532","and",120,123],["G0572","for your liberal",124,140],["G2842","distribution",141,153],["G1519","unto",154,158],["G0846","them",159,163],["G2532","and",165,168],["G1519","unto",169,173],["G3956","all",174,177]]},"9:14":{"text":"And by their prayer for you, which long after you for the exceeding grace of God in you.","words":[["G2532","And",0,3],["G0846","by their",4,12],["G1162","prayer",13,19],["G5228","for",20,23],["G5216","you",24,27],["G1971","which long after",29,45],["G5209","you",46,49],["G1223","for",50,53],["G5235","the exceeding",54,67],["G5485","grace",68,73],["G2316","of God",74,80],["G1909","in",81,83],["G5213","you",84,87]]},"9:15":{"text":"Thanks be unto God for his unspeakable gift.","words":[["G1161","",-1,-1],["G5485","Thanks",0,6],["G2316","be unto God",7,18],["G1909","for",19,22],["G0846","his",23,26],["G0411","unspeakable",27,38],["G1431","gift",39,43]]},"10:1":{"text":"Now I Paul myself beseech you by the meekness and gentleness of Christ, who in presence am base among you, but being absent am bold toward you:","words":[["G1161","Now",0,3],["G1473","I",4,5],["G3972","Paul",6,10],["G0846","myself",11,17],["G3870","beseech",18,25],["G5209","you",26,29],["G1223","by",30,32],["G4236","the meekness",33,45],["G2532","and",46,49],["G1932","gentleness",50,60],["G5547","of Christ",61,70],["G3739","who",72,75],["G2596","in",76,78],["G4383","presence",79,87],["G3303","am base",88,95],["G5011","am base",88,95],["G1722","among",96,101],["G5213","you",102,105],["G1161","but",107,110],["G0548","being absent",111,123],["G2292","am bold",124,131],["G1519","toward",132,138],["G5209","you",139,142]]},"10:2":{"text":"But I beseech you, that I may not be bold when I am present with that confidence, wherewith I think to be bold against some, which think of us as if we walked according to the flesh.","words":[["G1161","But",0,3],["G1189","I beseech",4,13],["G3361","you, that I may not",14,33],["G2292","be bold",34,41],["G3918","when I am present",42,59],["G4006","with that confidence",60,80],["G3739","wherewith",82,91],["G3049","I think",92,99],["G5111","to be bold",100,110],["G1909","against",111,118],["G5100","some",119,123],["G3588","which",125,130],["G3049","think",131,136],["G2248","of us",137,142],["G5613","as",143,145],["G4043","if we walked",146,158],["G2596","according",159,168],["G4561","to the flesh",169,181]]},"10:3":{"text":"For though we walk in the flesh, we do not war after the flesh:","words":[["G1063","For",0,3],["G4043","though we walk",4,18],["G1722","in",19,21],["G4561","the flesh",22,31],["G4754","we do",33,38],["G3756","not",39,42],["G4754","war",43,46],["G2596","after",47,52],["G4561","the flesh",53,62]]},"10:4":{"text":"(For the weapons of our warfare are not carnal, but mighty through God to the pulling down of strong holds;)","words":[["G1063","(For",0,4],["G3696","the weapons",5,16],["G2257","of our",17,23],["G4752","warfare",24,31],["G3756","are not",32,39],["G4559","carnal",40,46],["G0235","but",48,51],["G1415","mighty",52,58],["G2316","through God",59,70],["G4314","to",71,73],["G2506","the pulling down",74,90],["G3794","of strong holds",91,106]]},"10:5":{"text":"Casting down imaginations, and every high thing that exalteth itself against the knowledge of God, and bringing into captivity every thought to the obedience of Christ;","words":[["G2507","Casting down",0,12],["G3053","imaginations",13,25],["G2532","and",27,30],["G3956","every",31,36],["G5313","high thing",37,47],["G1869","that exalteth itself",48,68],["G2596","against",69,76],["G1108","the knowledge",77,90],["G2316","of God",91,97],["G2532","and",99,102],["G0163","bringing into captivity",103,126],["G3956","every",127,132],["G3540","thought",133,140],["G1519","to",141,143],["G5218","the obedience",144,157],["G5547","of Christ",158,167]]},"10:6":{"text":"And having in a readiness to revenge all disobedience, when your obedience is fulfilled.","words":[["G2532","And",0,3],["G2192","having",4,10],["G1722","in",11,13],["G2092","a readiness",14,25],["G1556","to revenge",26,36],["G3956","all",37,40],["G3876","disobedience",41,53],["G3752","when",55,59],["G5216","your",60,64],["G5218","obedience",65,74],["G4137","is fulfilled",75,87]]},"10:7":{"text":"Do ye look on things after the outward appearance? If any man trust to himself that he is Christ's, let him of himself think this again, that, as he is Christ's, even so are we Christ's.","words":[["G0991","Do ye look on",0,13],["G2596","things after",14,26],["G4383","the outward appearance",27,49],["G1536","If any man",51,61],["G3982","trust",62,67],["G1438","to himself",68,78],["G1511","that he is",79,89],["G5547","Christ's",90,98],["G3049","let him",100,107],["G0575","of",108,110],["G1438","himself",111,118],["G3049","think",119,124],["G5124","this",125,129],["G3825","again",130,135],["G3754","that",137,141],["G2531","as",143,145],["G0846","he",146,148],["G5547","is Christ's",149,160],["G2532","even",162,166],["G3779","so",167,169],["G2249","are we",170,176],["G5547","Christ's",177,185]]},"10:8":{"text":"For though I should boast somewhat more of our authority, which the Lord hath given us for edification, and not for your destruction, I should not be ashamed:","words":[["G1063","For",0,3],["G2532","For",0,3],["G1437","though",4,10],["G5037","though",4,10],["G2744","I should boast",11,25],["G5100","somewhat",26,34],["G4055","more",35,39],["G4012","of",40,42],["G2257","our",43,46],["G1849","authority",47,56],["G3739","which",58,63],["G2962","the Lord",64,72],["G1325","hath given",73,83],["G2254","us",84,86],["G1519","for",87,90],["G3619","edification",91,102],["G2532","and",104,107],["G3756","not",108,111],["G1519","for",112,115],["G5216","your",116,120],["G2506","destruction",121,132],["G0153","I should",134,142],["G3756","not",143,146],["G0153","be ashamed",147,157]]},"10:9":{"text":"That I may not seem as if I would terrify you by letters.","words":[["G3363","That",0,4],["G1380","I may",5,10],["G3363","not",11,14],["G1380","seem",15,19],["G5613","as",20,22],["G0302","if",23,25],["G1629","I would terrify",26,41],["G5209","you",42,45],["G1223","by",46,48],["G1992","letters",49,56]]},"10:10":{"text":"For his letters, say they, are weighty and powerful; but his bodily presence is weak, and his speech contemptible.","words":[["G3754","For",0,3],["G1992","his letters",4,15],["G3303","his letters",4,15],["G5346","say they",17,25],["G0926","are weighty",27,38],["G2532","and",39,42],["G2478","powerful",43,51],["G1161","but",53,56],["G4983","his bodily",57,67],["G3952","presence",68,76],["G0772","is weak",77,84],["G2532","and",86,89],["G3056","his speech",90,100],["G1848","contemptible",101,113]]},"10:11":{"text":"Let such an one think this, that, such as we are in word by letters when we are absent, such will we be also in deed when we are present.","words":[["G3049","Let",0,3],["G5108","such an one",4,15],["G3049","think",16,21],["G5124","this",22,26],["G3754","that",28,32],["G3634","such as",34,41],["G2070","we are",42,48],["G3056","in word",49,56],["G1223","by",57,59],["G1992","letters",60,67],["G0548","when we are absent",68,86],["G5108","such",88,92],["G2532","will we be also",93,108],["G2041","in deed",109,116],["G3918","when we are present",117,136]]},"10:12":{"text":"For we dare not make ourselves of the number, or compare ourselves with some that commend themselves: but they measuring themselves by themselves, and comparing themselves among themselves, are not wise.","words":[["G1063","For",0,3],["G5111","we dare",4,11],["G3756","not",12,15],["G1469","make",16,20],["G1469","ourselves of the number",21,44],["G2228","or",46,48],["G4793","compare",49,56],["G1438","ourselves",57,66],["G4793","with",67,71],["G5100","some",72,76],["G4921","that commend",77,89],["G1438","themselves",90,100],["G0235","but",102,105],["G0846","they",106,110],["G3354","measuring",111,120],["G1438","themselves",121,131],["G1722","by",132,134],["G1438","themselves",135,145],["G2532","and",147,150],["G4793","comparing",151,160],["G1438","themselves",161,171],["G4793","among",172,177],["G1438","themselves",178,188],["G4920","are",190,193],["G3756","not",194,197],["G4920","wise",198,202]]},"10:13":{"text":"But we will not boast of things without our measure, but according to the measure of the rule which God hath distributed to us, a measure to reach even unto you.","words":[["G1161","But",0,3],["G2249","we",4,6],["G2744","will",7,11],["G3780","not",12,15],["G2744","boast",16,21],["G1519","of things without",22,39],["G0280","our measure",40,51],["G0235","but",53,56],["G2596","according",57,66],["G3358","to the measure",67,81],["G2583","of the rule",82,93],["G3739","which",94,99],["G2316","God",100,103],["G3307","hath distributed",104,120],["G2254","to us",121,126],["G3358","a measure",128,137],["G2185","to reach",138,146],["G2532","even",147,151],["G0891","unto",152,156],["G5216","you",157,160]]},"10:14":{"text":"For we stretch not ourselves beyond our measure, as though we reached not unto you: for we are come as far as to you also in preaching the gospel of Christ:","words":[["G1063","For",0,3],["G5239","we stretch",4,14],["G3756","not",15,18],["G1438","ourselves",19,28],["G5239","beyond",29,35],["G5613","our measure, as",36,51],["G2185","though we reached",52,69],["G3361","not",70,73],["G1519","unto",74,78],["G5209","you",79,82],["G1063","for",84,87],["G5348","we are come",88,99],["G0891","as far as",100,109],["G5216","to you",110,116],["G2532","also",117,121],["G1722","in",122,124],["G2098","preaching the gospel",125,145],["G5547","of Christ",146,155]]},"10:15":{"text":"Not boasting of things without our measure, that is, of other men's labours; but having hope, when your faith is increased, that we shall be enlarged by you according to our rule abundantly,","words":[["G3756","Not",0,3],["G2744","boasting",4,12],["G1519","of things without",13,30],["G0280","our measure",31,42],["G1722","that is, of",44,55],["G0245","other men's",56,67],["G2873","labours",68,75],["G1161","but",77,80],["G2192","having",81,87],["G1680","hope",88,92],["G5216","when your",94,103],["G4102","faith",104,109],["G0837","is increased",110,122],["G3170","that we shall be enlarged",124,149],["G1722","by",150,152],["G5213","you",153,156],["G2596","according",157,166],["G2257","to our",167,173],["G2583","rule",174,178],["G1519","abundantly",179,189],["G4050","abundantly",179,189]]},"10:16":{"text":"To preach the gospel in the regions beyond you, and not to boast in another man's line of things made ready to our hand.","words":[["G2097","To preach the gospel",0,20],["G1519","in",21,23],["G5238","the regions beyond",24,42],["G5216","you",43,46],["G3756","and not",48,55],["G2744","to boast",56,64],["G1722","in",65,67],["G0245","another man's",68,81],["G2583","line",82,86],["G1519","of",87,89],["G2092","things made ready to our hand",90,119]]},"10:17":{"text":"But he that glorieth, let him glory in the Lord.","words":[["G1161","But",0,3],["G2744","he that glorieth",4,20],["G2744","let him glory",22,35],["G1722","in",36,38],["G2962","the Lord",39,47]]},"10:18":{"text":"For not he that commendeth himself is approved, but whom the Lord commendeth.","words":[["G1063","For",0,3],["G3756","not",4,7],["G1565","he",8,10],["G4921","that commendeth",11,26],["G1438","himself",27,34],["G2076","is",35,37],["G1384","approved",38,46],["G0235","but",48,51],["G3739","whom",52,56],["G2962","the Lord",57,65],["G4921","commendeth",66,76]]},"11:1":{"text":"Would to God ye could bear with me a little in my folly: and indeed bear with me.","words":[["G3785","Would to God",0,12],["G0430","ye could bear",13,26],["G3450","with me",27,34],["G3397","a little",35,43],["G0877","in my folly",44,55],["G2532","and",57,60],["G0235","indeed",61,67],["G0430","bear",68,72],["G3450","with me",73,80]]},"11:2":{"text":"For I am jealous over you with godly jealousy: for I have espoused you to one husband, that I may present you as a chaste virgin to Christ.","words":[["G1063","For",0,3],["G2206","I am jealous",4,16],["G5209","over you",17,25],["G2316","with godly",26,36],["G2205","jealousy",37,45],["G1063","for",47,50],["G0718","I have espoused",51,66],["G5209","you",67,70],["G1520","to one",71,77],["G0435","husband",78,85],["G3936","that I may present",87,105],["G0053","you as a chaste",106,121],["G3933","virgin",122,128],["G5547","to Christ",129,138]]},"11:3":{"text":"But I fear, lest by any means, as the serpent beguiled Eve through his subtilty, so your minds should be corrupted from the simplicity that is in Christ.","words":[["G1161","But",0,3],["G5399","I fear",4,10],["G3381","lest",12,16],["G4458","by any means",17,29],["G5613","as",31,33],["G3789","the serpent",34,45],["G1818","beguiled",46,54],["G2096","Eve",55,58],["G1722","through",59,66],["G0846","his",67,70],["G3834","subtilty",71,79],["G3779","so",81,83],["G5216","your",84,88],["G3540","minds",89,94],["G5351","should be corrupted",95,114],["G0575","from",115,119],["G0572","the simplicity",120,134],["G1519","that is in",135,145],["G5547","Christ",146,152]]},"11:4":{"text":"For if he that cometh preacheth another Jesus, whom we have not preached, or if ye receive another spirit, which ye have not received, or another gospel, which ye have not accepted, ye might well bear with him.","words":[["G1063","For",0,3],["G1487","if",4,6],["G3303","if",4,6],["G2064","he that cometh",7,21],["G2784","preacheth",22,31],["G0243","another",32,39],["G2424","Jesus",40,45],["G3739","whom",47,51],["G2784","we have",52,59],["G3756","not",60,63],["G2784","preached",64,72],["G2228","or",74,76],["G2983","if ye receive",77,90],["G2087","another",91,98],["G4151","spirit",99,105],["G3739","which",107,112],["G2983","ye have",113,120],["G3756","not",121,124],["G2983","received",125,133],["G2228","or",135,137],["G2087","another",138,145],["G2098","gospel",146,152],["G3739","which",154,159],["G1209","ye have",160,167],["G3756","not",168,171],["G1209","accepted",172,180],["G0430","ye might",182,190],["G2573","well",191,195],["G0430","bear with",196,205]]},"11:5":{"text":"For I suppose I was not a whit behind the very chiefest apostles.","words":[["G1063","For",0,3],["G3049","I suppose",4,13],["G5302","I was",14,19],["G3367","not a whit",20,30],["G5302","behind",31,37],["G5228","the very",38,46],["G3029","chiefest",47,55],["G0652","apostles",56,64]]},"11:6":{"text":"But though I be rude in speech, yet not in knowledge; but we have been throughly made manifest among you in all things.","words":[["G1161","But",0,3],["G1499","though",4,10],["G2399","I be rude",11,20],["G3056","in speech",21,30],["G0235","yet",32,35],["G3756","not",36,39],["G1108","in knowledge",40,52],["G0235","but",54,57],["G1722","we have been throughly",58,80],["G3956","we have been throughly",58,80],["G5319","made manifest",81,94],["G1519","among",95,100],["G5209","you",101,104],["G1722","in",105,107],["G3956","all things",108,118]]},"11:7":{"text":"Have I committed an offence in abasing myself that ye might be exalted, because I have preached to you the gospel of God freely?","words":[["G2228","",-1,-1],["G4160","Have I committed",0,16],["G0266","an offence",17,27],["G5013","in abasing",28,38],["G1683","myself",39,45],["G2443","that",46,50],["G5210","ye",51,53],["G5312","might be exalted",54,70],["G3754","because",72,79],["G2097","I have preached",80,95],["G5213","to you",96,102],["G2098","the gospel",103,113],["G2316","of God",114,120],["G1432","freely",121,127]]},"11:8":{"text":"I robbed other churches, taking wages of them, to do you service.","words":[["G4813","I robbed",0,8],["G0243","other",9,14],["G1577","churches",15,23],["G2983","taking",25,31],["G3800","wages",32,37],["G4314","of them, to",38,49],["G1248","do",50,52],["G5216","you",53,56],["G1248","service",57,64]]},"11:9":{"text":"And when I was present with you, and wanted, I was chargeable to no man: for that which was lacking to me the brethren which came from Macedonia supplied: and in all things I have kept myself from being burdensome unto you, and so will I keep myself.","words":[["G2532","And",0,3],["G3918","when I was present",4,22],["G4314","with",23,27],["G5209","you",28,31],["G2532","and",33,36],["G5302","wanted",37,43],["G3756","I was",45,50],["G2655","chargeable",51,61],["G3762","to no man",62,71],["G1063","for",73,76],["G5303","that which was lacking",77,99],["G3450","to me",100,105],["G0080","the brethren",106,118],["G2064","which came",119,129],["G0575","from",130,134],["G3109","Macedonia",135,144],["G4322","supplied",145,153],["G2532","and",155,158],["G1722","in",159,161],["G3956","all",162,165],["G5083","things I have kept",166,184],["G1683","myself",185,191],["G0004","from being burdensome",192,213],["G5213","unto you",214,222],["G2532","and",224,227],["G5083","so will I keep",228,242]]},"11:10":{"text":"As the truth of Christ is in me, no man shall stop me of this boasting in the regions of Achaia.","words":[["G0225","As the truth",0,12],["G5547","of Christ",13,22],["G2076","is",23,25],["G1722","in",26,28],["G1698","me",29,31],["G3754","",-1,-1],["G3756","no man",33,39],["G4972","shall stop",40,50],["G5420","shall stop",40,50],["G1519","me",51,53],["G1691","me",51,53],["G3778","of this",54,61],["G2746","boasting",62,70],["G1722","in",71,73],["G2824","the regions",74,85],["G0882","of Achaia",86,95]]},"11:11":{"text":"Wherefore? because I love you not? God knoweth.","words":[["G1302","Wherefore",0,9],["G3754","because",11,18],["G0025","I love",19,25],["G5209","you",26,29],["G3756","not",30,33],["G2316","God",35,38],["G1492","knoweth",39,46]]},"11:12":{"text":"But what I do, that I will do, that I may cut off occasion from them which desire occasion; that wherein they glory, they may be found even as we.","words":[["G1161","But",0,3],["G3739","what",4,8],["G4160","I do",9,13],["G2532","that",15,19],["G4160","I will do",20,29],["G2443","that",31,35],["G1581","I may cut off",36,49],["G0874","occasion",50,58],["G2309","from them which desire",59,81],["G0874","occasion",82,90],["G2443","that",92,96],["G1722","wherein",97,104],["G3739","wherein",97,104],["G2744","they glory",105,115],["G2147","they may be found",117,134],["G2532","even",135,139],["G2531","as",140,142],["G2249","we",143,145]]},"11:13":{"text":"For such are false apostles, deceitful workers, transforming themselves into the apostles of Christ.","words":[["G1063","For",0,3],["G5108","such",4,8],["G5570","are false apostles",9,27],["G1386","deceitful",29,38],["G2040","workers",39,46],["G3345","transforming themselves",48,71],["G1519","into",72,76],["G0652","the apostles",77,89],["G5547","of Christ",90,99]]},"11:14":{"text":"And no marvel; for Satan himself is transformed into an angel of light.","words":[["G2532","And",0,3],["G3756","no",4,6],["G2298","marvel",7,13],["G1063","for",15,18],["G4567","Satan",19,24],["G0846","himself",25,32],["G3345","is transformed",33,47],["G1519","into",48,52],["G0032","an angel",53,61],["G5457","of light",62,70]]},"11:15":{"text":"Therefore it is no great thing if his ministers also be transformed as the ministers of righteousness; whose end shall be according to their works.","words":[["G3767","Therefore",0,9],["G3756","it is no",10,18],["G3173","great thing",19,30],["G1499","if",31,33],["G0846","his",34,37],["G1249","ministers",38,47],["G1499","also",48,52],["G3345","be transformed",53,67],["G5613","as",68,70],["G1249","the ministers",71,84],["G1343","of righteousness",85,101],["G3739","whose",103,108],["G5056","end",109,112],["G2071","shall be",113,121],["G2596","according",122,131],["G0846","to their",132,140],["G2041","works",141,146]]},"11:16":{"text":"I say again, Let no man think me a fool; if otherwise, yet as a fool receive me, that I may boast myself a little.","words":[["G3004","I say",0,5],["G3825","again",6,11],["G1380","Let",13,16],["G3361","no",17,19],["G5100","man",20,23],["G1380","think",24,29],["G1511","me",30,32],["G3165","me",30,32],["G0878","a fool",33,39],["G1490","if otherwise",41,53],["G2579","yet",55,58],["G5613","as",59,61],["G0878","a fool",62,68],["G1209","receive",69,76],["G3165","me",77,79],["G2443","that",81,85],["G2504","I",86,87],["G2744","may boast myself",88,104],["G5100","a",105,106],["G3397","little",107,113]]},"11:17":{"text":"That which I speak, I speak it not after the Lord, but as it were foolishly, in this confidence of boasting.","words":[["G3739","That which",0,10],["G2980","I speak",11,18],["G2980","I speak",20,27],["G3756","it not",28,34],["G2596","after",35,40],["G2962","the Lord",41,49],["G0235","but",51,54],["G5613","as",55,57],["G1722","it were foolishly",58,75],["G0877","it were foolishly",58,75],["G1722","in",77,79],["G5026","this",80,84],["G5287","confidence",85,95],["G2746","of boasting",96,107]]},"11:18":{"text":"Seeing that many glory after the flesh, I will glory also.","words":[["G1893","Seeing that",0,11],["G4183","many",12,16],["G2744","glory",17,22],["G2596","after",23,28],["G4561","the flesh",29,38],["G2744","I will glory",40,52],["G2504","also",53,57]]},"11:19":{"text":"For ye suffer fools gladly, seeing ye yourselves are wise.","words":[["G1063","For",0,3],["G0430","ye suffer",4,13],["G0878","fools",14,19],["G2234","gladly",20,26],["G5607","seeing ye yourselves are",28,52],["G5429","wise",53,57]]},"11:20":{"text":"For ye suffer, if a man bring you into bondage, if a man devour you, if a man take of you, if a man exalt himself, if a man smite you on the face.","words":[["G1063","For",0,3],["G0430","ye suffer",4,13],["G1536","if a man",15,23],["G2615","bring",24,29],["G5209","you",30,33],["G2615","into bondage",34,46],["G1536","if a man",48,56],["G2719","devour",57,63],["G1536","you, if a man",64,77],["G2983","take",78,82],["G1536","of you, if a man",83,99],["G1869","exalt himself",100,113],["G1536","if a man",115,123],["G1194","smite",124,129],["G5209","you",130,133],["G1519","on",134,136],["G4383","the face",137,145]]},"11:21":{"text":"I speak as concerning reproach, as though we had been weak. Howbeit whereinsoever any is bold, (I speak foolishly,) I am bold also.","words":[["G3004","I speak",0,7],["G2596","as concerning",8,21],["G0819","reproach",22,30],["G5613","as",32,34],["G3754","though",35,41],["G2249","we",42,44],["G0770","had been weak",45,58],["G1161","Howbeit",60,67],["G1722","whereinsoever",68,81],["G3739","whereinsoever",68,81],["G0302","whereinsoever",68,81],["G5100","any",82,85],["G5111","is bold",86,93],["G3004","(I speak",95,103],["G1722","foolishly",104,113],["G0877","foolishly",104,113],["G5111",") I am bold",114,125],["G2504","also",126,130]]},"11:22":{"text":"Are they Hebrews? so am I. Are they Israelites? so am I. Are they the seed of Abraham? so am I.","words":[["G1526","Are they",0,8],["G1445","Hebrews",9,16],["G2504","so am I",18,25],["G1526","Are they",27,35],["G2475","Israelites",36,46],["G2504","so am I",48,55],["G1526","Are they",57,65],["G4690","the seed",66,74],["G0011","of Abraham",75,85],["G2504","so am I",87,94]]},"11:23":{"text":"Are they ministers of Christ? (I speak as a fool) I am more; in labours more abundant, in stripes above measure, in prisons more frequent, in deaths oft.","words":[["G1526","Are they",0,8],["G1249","ministers",9,18],["G5547","of Christ",19,28],["G2980","(I speak",30,38],["G3912","as a fool",39,48],["G1473","I",50,51],["G5228","am more",52,59],["G1722","in",61,63],["G2873","labours",64,71],["G4056","more abundant",72,85],["G1722","in",87,89],["G4127","stripes",90,97],["G5234","above measure",98,111],["G1722","in",113,115],["G5438","prisons",116,123],["G4056","more frequent",124,137],["G1722","in",139,141],["G2288","deaths",142,148],["G4178","oft",149,152]]},"11:24":{"text":"Of the Jews five times received I forty stripes save one.","words":[["G5259","Of",0,2],["G2453","the Jews",3,11],["G3999","five times",12,22],["G2983","received I",23,33],["G5062","forty",34,39],["G3844","stripes save",40,52],["G3391","one",53,56]]},"11:25":{"text":"Thrice was I beaten with rods, once was I stoned, thrice I suffered shipwreck, a night and a day I have been in the deep;","words":[["G5151","Thrice",0,6],["G4463","was I beaten with rods",7,29],["G0530","once",31,35],["G3034","was I stoned",36,48],["G5151","thrice",50,56],["G3489","I suffered shipwreck",57,77],["G3574","a night and a day",79,96],["G4160","I have been",97,108],["G1722","in",109,111],["G1037","the deep",112,120]]},"11:26":{"text":"In journeyings often, in perils of waters, in perils of robbers, in perils by mine own countrymen, in perils by the heathen, in perils in the city, in perils in the wilderness, in perils in the sea, in perils among false brethren;","words":[["G3597","In journeyings",0,14],["G4178","often",15,20],["G2794","in perils",22,31],["G4215","of waters",32,41],["G2794","in perils",43,52],["G3027","of robbers",53,63],["G2794","in perils",65,74],["G1537","by",75,77],["G1085","mine own countrymen",78,97],["G2794","in perils",99,108],["G1537","by",109,111],["G1484","the heathen",112,123],["G2794","in perils",125,134],["G1722","in",135,137],["G4172","the city",138,146],["G2794","in perils",148,157],["G1722","in",158,160],["G2047","the wilderness",161,175],["G2794","in perils",177,186],["G1722","in",187,189],["G2281","the sea",190,197],["G2794","in perils",199,208],["G1722","among",209,214],["G5569","false brethren",215,229]]},"11:27":{"text":"In weariness and painfulness, in watchings often, in hunger and thirst, in fastings often, in cold and nakedness.","words":[["G1722","In",0,2],["G2873","weariness",3,12],["G2532","and",13,16],["G3449","painfulness",17,28],["G1722","in",30,32],["G0070","watchings",33,42],["G4178","often",43,48],["G1722","in",50,52],["G3042","hunger",53,59],["G2532","and",60,63],["G1373","thirst",64,70],["G1722","in",72,74],["G3521","fastings",75,83],["G4178","often",84,89],["G1722","in",91,93],["G5592","cold",94,98],["G2532","and",99,102],["G1132","nakedness",103,112]]},"11:28":{"text":"Beside those things that are without, that which cometh upon me daily, the care of all the churches.","words":[["G5565","Beside",0,6],["G3924","those things that are without",7,36],["G3588","that which",38,48],["G1999","cometh upon",49,60],["G3450","me",61,63],["G2250","daily",64,69],["G2596","",-1,-1],["G3308","the care",71,79],["G3956","of all",80,86],["G1577","the churches",87,99]]},"11:29":{"text":"Who is weak, and I am not weak? who is offended, and I burn not?","words":[["G5101","Who",0,3],["G0770","is weak",4,11],["G2532","and",13,16],["G0770","I am",17,21],["G3756","not",22,25],["G0770","weak",26,30],["G5101","who",32,35],["G4624","is offended",36,47],["G2532","and",49,52],["G1473","I",53,54],["G4448","burn",55,59],["G3756","not",60,63]]},"11:30":{"text":"If I must needs glory, I will glory of the things which concern mine infirmities.","words":[["G1487","If",0,2],["G1163","I must needs",3,15],["G2744","glory",16,21],["G2744","I will glory",23,35],["G3588","of the things which concern",36,63],["G3450","mine",64,68],["G0769","infirmities",69,80]]},"11:31":{"text":"The God and Father of our Lord Jesus Christ, which is blessed for evermore, knoweth that I lie not.","words":[["G2316","The God",0,7],["G2532","and",8,11],["G3962","Father",12,18],["G2257","of our",19,25],["G2962","Lord",26,30],["G2424","Jesus",31,36],["G5547","Christ",37,43],["G3588","which",45,50],["G5607","is",51,53],["G2128","blessed",54,61],["G1519","for",62,65],["G0165","evermore",66,74],["G1492","knoweth",76,83],["G3754","that I",84,90],["G5574","lie",91,94],["G3756","not",95,98]]},"11:32":{"text":"In Damascus the governor under Aretas the king kept the city of the Damascenes with a garrison, desirous to apprehend me:","words":[["G1722","In",0,2],["G1154","Damascus",3,11],["G1481","the governor",12,24],["G0702","under Aretas",25,37],["G0935","the king",38,46],["G5432","kept",47,51],["G4172","the city",52,60],["G1153","of the Damascenes",61,78],["G5432","with a garrison",79,94],["G2309","desirous",96,104],["G4084","to apprehend",105,117],["G3165","me",118,120]]},"11:33":{"text":"And through a window in a basket was I let down by the wall, and escaped his hands.","words":[["G2532","And",0,3],["G1223","through",4,11],["G2376","a window",12,20],["G1722","in",21,23],["G4553","a basket",24,32],["G5465","was I let down",33,47],["G1223","by",48,50],["G5038","the wall",51,59],["G2532","and",61,64],["G1628","escaped",65,72],["G0846","his",73,76],["G5495","hands",77,82]]},"12:1":{"text":"It is not expedient for me doubtless to glory. I will come to visions and revelations of the Lord.","words":[["G4851","It is",0,5],["G3756","not",6,9],["G4851","expedient",10,19],["G3427","for me",20,26],["G1211","doubtless",27,36],["G2744","to glory",37,45],["G1063","",-1,-1],["G2064","I will come",47,58],["G1519","to",59,61],["G3701","visions",62,69],["G2532","and",70,73],["G0602","revelations",74,85],["G2962","of the Lord",86,97]]},"12:2":{"text":"I knew a man in Christ above fourteen years ago, (whether in the body, I cannot tell; or whether out of the body, I cannot tell: God knoweth;) such an one caught up to the third heaven.","words":[["G1492","I knew",0,6],["G0444","a man",7,12],["G1722","in",13,15],["G5547","Christ",16,22],["G4253","above",23,28],["G1180","fourteen",29,37],["G2094","years",38,43],["G4253","ago",44,47],["G1535","(whether",49,57],["G1722","in",58,60],["G4983","the body",61,69],["G3756","I cannot",71,79],["G1492","tell",80,84],["G1535","or whether",86,96],["G1622","out",97,100],["G4983","of the body",101,112],["G3756","I cannot",114,122],["G1492","tell",123,127],["G2316","God",129,132],["G1492","knoweth",133,140],["G5108",") such an one",141,154],["G0726","caught up",155,164],["G2193","to",165,167],["G5154","the third",168,177],["G3772","heaven",178,184]]},"12:3":{"text":"And I knew such a man, (whether in the body, or out of the body, I cannot tell: God knoweth;)","words":[["G2532","And",0,3],["G1492","I knew",4,10],["G5108","such",11,15],["G0444","a man",16,21],["G1535","(whether",23,31],["G1722","in",32,34],["G4983","the body",35,43],["G1535","or",45,47],["G1622","out",48,51],["G4983","of the body",52,63],["G3756","I cannot",65,73],["G1492","tell",74,78],["G2316","God",80,83],["G1492","knoweth",84,91]]},"12:4":{"text":"How that he was caught up into paradise, and heard unspeakable words, which it is not lawful for a man to utter.","words":[["G3754","How that",0,8],["G0726","he was caught up",9,25],["G1519","into",26,30],["G3857","paradise",31,39],["G2532","and",41,44],["G0191","heard",45,50],["G0731","unspeakable",51,62],["G4487","words",63,68],["G3739","which",70,75],["G1832","it is",76,81],["G3756","not",82,85],["G1832","lawful",86,92],["G0444","for a man",93,102],["G2980","to utter",103,111]]},"12:5":{"text":"Of such an one will I glory: yet of myself I will not glory, but in mine infirmities.","words":[["G5228","Of",0,2],["G5108","such an one",3,14],["G2744","will I glory",15,27],["G1161","yet",29,32],["G5228","of",33,35],["G1683","myself",36,42],["G2744","I will",43,49],["G3756","not",50,53],["G2744","glory",54,59],["G1508","but",61,64],["G1722","in",65,67],["G3450","mine",68,72],["G0769","infirmities",73,84]]},"12:6":{"text":"For though I would desire to glory, I shall not be a fool; for I will say the truth: but now I forbear, lest any man should think of me above that which he seeth me to be, or that he heareth of me.","words":[["G1063","For",0,3],["G1437","though",4,10],["G2309","I would desire",11,25],["G2744","to glory",26,34],["G2071","I shall",36,43],["G3756","not",44,47],["G2071","be",48,50],["G0878","a fool",51,57],["G1063","for",59,62],["G2046","I will say",63,73],["G0225","the truth",74,83],["G1161","but",85,88],["G5339","now I forbear",89,102],["G3361","lest",104,108],["G5100","any man",109,116],["G3049","should think",117,129],["G1519","of",130,132],["G1691","me",133,135],["G5228","above",136,141],["G3739","that which",142,152],["G0991","he seeth",153,161],["G3165","me",162,164],["G2228","to be, or",165,174],["G0191","that he heareth",175,190],["G5100","of",191,193],["G1537","of",191,193],["G1700","me",194,196]]},"12:7":{"text":"And lest I should be exalted above measure through the abundance of the revelations, there was given to me a thorn in the flesh, the messenger of Satan to buffet me, lest I should be exalted above measure.","words":[["G2532","And",0,3],["G3363","lest",4,8],["G5229","I should be exalted above measure",9,42],["G5236","through the abundance",43,64],["G0602","of the revelations",65,83],["G1325","there was given",85,100],["G3427","to me",101,106],["G4647","a thorn",107,114],["G4561","in the flesh",115,127],["G0032","the messenger",129,142],["G4566","of Satan",143,151],["G2443","to",152,154],["G2852","buffet",155,161],["G3165","me",162,164],["G3363","lest",166,170],["G5229","I should be exalted above measure",171,204]]},"12:8":{"text":"For this thing I besought the Lord thrice, that it might depart from me.","words":[["G5228","For",0,3],["G5127","this thing",4,14],["G3870","I besought",15,25],["G2962","the Lord",26,34],["G5151","thrice",35,41],["G2443","that",43,47],["G0868","it might depart",48,63],["G0575","from",64,68],["G1700","me",69,71]]},"12:9":{"text":"And he said unto me, My grace is sufficient for thee: for my strength is made perfect in weakness. Most gladly therefore will I rather glory in my infirmities, that the power of Christ may rest upon me.","words":[["G2532","And",0,3],["G2046","he said",4,11],["G3427","unto me",12,19],["G3450","My",21,23],["G5485","grace",24,29],["G0714","is sufficient",30,43],["G4671","for thee",44,52],["G1063","for",54,57],["G3450","my",58,60],["G1411","strength",61,69],["G5048","is made perfect",70,85],["G1722","in",86,88],["G0769","weakness",89,97],["G2236","Most gladly",99,110],["G3767","therefore",111,120],["G2744","will I",121,127],["G3123","rather",128,134],["G2744","glory",135,140],["G1722","in",141,143],["G3450","my",144,146],["G0769","infirmities",147,158],["G2443","that",160,164],["G1411","the power",165,174],["G5547","of Christ",175,184],["G1981","may rest",185,193],["G1909","upon",194,198],["G1691","me",199,201]]},"12:10":{"text":"Therefore I take pleasure in infirmities, in reproaches, in necessities, in persecutions, in distresses for Christ's sake: for when I am weak, then am I strong.","words":[["G1352","Therefore",0,9],["G2106","I take pleasure",10,25],["G1722","in",26,28],["G0769","infirmities",29,40],["G1722","in",42,44],["G5196","reproaches",45,55],["G1722","in",57,59],["G0318","necessities",60,71],["G1722","in",73,75],["G1375","persecutions",76,88],["G1722","in",90,92],["G4730","distresses",93,103],["G5228","for",104,107],["G5547","Christ's",108,116],["G5228","sake",117,121],["G1063","for",123,126],["G3752","when",127,131],["G0770","I am weak",132,141],["G5119","then",143,147],["G1510","am",148,150],["G1415","I strong",151,159]]},"12:11":{"text":"I am become a fool in glorying; ye have compelled me: for I ought to have been commended of you: for in nothing am I behind the very chiefest apostles, though I be nothing.","words":[["G1096","I am become",0,11],["G0878","a fool",12,18],["G2744","in glorying",19,30],["G5210","ye",32,34],["G0315","have compelled",35,49],["G3165","me",50,52],["G1063","for",54,57],["G1473","I",58,59],["G3784","ought",60,65],["G4921","to have been commended",66,88],["G5259","of",89,91],["G5216","you",92,95],["G1063","for",97,100],["G3762","in nothing",101,111],["G5302","am I behind",112,123],["G3029","the very chiefest",124,141],["G0652","apostles",142,150],["G5228","apostles",142,150],["G1499","though",152,158],["G1510","I be",159,163],["G3762","nothing",164,171]]},"12:12":{"text":"Truly the signs of an apostle were wrought among you in all patience, in signs, and wonders, and mighty deeds.","words":[["G3303","Truly",0,5],["G4592","the signs",6,15],["G0652","of an apostle",16,29],["G2716","were wrought",30,42],["G1722","among",43,48],["G5213","you",49,52],["G1722","in",53,55],["G3956","all",56,59],["G5281","patience",60,68],["G1722","in",70,72],["G4592","signs",73,78],["G2532","and",80,83],["G5059","wonders",84,91],["G2532","and",93,96],["G1411","mighty deeds",97,109]]},"12:13":{"text":"For what is it wherein ye were inferior to other churches, except it be that I myself was not burdensome to you? forgive me this wrong.","words":[["G1063","For",0,3],["G5101","what",4,8],["G2076","is it",9,14],["G3739","wherein",15,22],["G2274","ye were inferior",23,39],["G5228","to",40,42],["G3062","other",43,48],["G1577","churches",49,57],["G1508","except",59,65],["G3754","it be that",66,76],["G1473","I",77,78],["G0846","myself",79,85],["G2655","was",86,89],["G3756","not",90,93],["G2655","burdensome",94,104],["G5216","to you",105,111],["G5483","forgive",113,120],["G3427","me",121,123],["G5026","this",124,128],["G0093","wrong",129,134]]},"12:14":{"text":"Behold, the third time I am ready to come to you; and I will not be burdensome to you: for I seek not yours, but you: for the children ought not to lay up for the parents, but the parents for the children.","words":[["G2400","Behold",0,6],["G5154","the third time",8,22],["G2192","I am",23,27],["G2093","ready",28,33],["G2064","to come",34,41],["G4314","to",42,44],["G5209","you",45,48],["G2532","and",50,53],["G2655","I will",54,60],["G3756","not",61,64],["G2655","be burdensome",65,78],["G5216","to you",79,85],["G1063","for",87,90],["G2212","I seek",91,97],["G3756","not",98,101],["G5216","yours",102,107],["G0235","but",109,112],["G5209","you",113,116],["G1063","for",118,121],["G5043","the children",122,134],["G3784","ought",135,140],["G3756","not",141,144],["G2343","to lay up",145,154],["G1118","for the parents",155,170],["G0235","but",172,175],["G1118","the parents",176,187],["G5043","for the children",188,204]]},"12:15":{"text":"And I will very gladly spend and be spent for you; though the more abundantly I love you, the less I be loved.","words":[["G1161","And",0,3],["G1473","I",4,5],["G2236","will very gladly",6,22],["G1159","spend",23,28],["G2532","and",29,32],["G1550","be spent",33,41],["G5228","for",42,45],["G5590","you",46,49],["G5216","you",46,49],["G1499","though",51,57],["G4056","the more abundantly",58,77],["G0025","I love",78,84],["G5209","you",85,88],["G2276","the less",90,98],["G0025","I be loved",99,109]]},"12:16":{"text":"But be it so, I did not burden you: nevertheless, being crafty, I caught you with guile.","words":[["G1161","But",0,3],["G2077","be it so",4,12],["G1473","I",14,15],["G2599","did",16,19],["G3756","not",20,23],["G2599","burden",24,30],["G5209","you",31,34],["G0235","nevertheless",36,48],["G5225","being",50,55],["G3835","crafty",56,62],["G2983","I caught",64,72],["G5209","you",73,76],["G1388","with guile",77,87]]},"12:17":{"text":"Did I make a gain of you by any of them whom I sent unto you?","words":[["G4122","Did I make a gain",0,17],["G3361","Did I make a gain",0,17],["G5209","of you",18,24],["G1223","by",25,27],["G5100","any",28,31],["G0846","of them",32,39],["G3739","whom",40,44],["G0649","I sent",45,51],["G4314","unto",52,56],["G5209","you",57,60]]},"12:18":{"text":"I desired Titus, and with him I sent a brother. Did Titus make a gain of you? walked we not in the same spirit? walked we not in the same steps?","words":[["G3870","I desired",0,9],["G5103","Titus",10,15],["G2532","and",17,20],["G4882","with him I sent",21,36],["G0080","a brother",37,46],["G4122","Did",48,51],["G3387","Did",48,51],["G5103","Titus",52,57],["G4122","make a gain",58,69],["G5209","of you",70,76],["G4043","walked we",78,87],["G3756","not",88,91],["G0846","in the same",92,103],["G4151","spirit",104,110],["G3756","walked we not",112,125],["G0846","in the same",126,137],["G2487","steps",138,143]]},"12:19":{"text":"Again, think ye that we excuse ourselves unto you? we speak before God in Christ: but we do all things, dearly beloved, for your edifying.","words":[["G3825","Again",0,5],["G1380","think ye",7,15],["G3754","that",16,20],["G0626","we excuse ourselves",21,40],["G5213","unto you",41,49],["G2980","we speak",51,59],["G2714","before",60,66],["G2316","God",67,70],["G1722","in",71,73],["G5547","Christ",74,80],["G1161","but",82,85],["G3956","we do all things",86,102],["G0027","dearly beloved",104,118],["G5228","for",120,123],["G5216","your",124,128],["G3619","edifying",129,137]]},"12:20":{"text":"For I fear, lest, when I come, I shall not find you such as I would, and that I shall be found unto you such as ye would not: lest there be debates, envyings, wraths, strifes, backbitings, whisperings, swellings, tumults:","words":[["G1063","For",0,3],["G5399","I fear",4,10],["G3381","lest",12,16],["G4458","lest",12,16],["G2064","when I come",18,29],["G2147","I shall",31,38],["G3756","not",39,42],["G2147","find",43,47],["G5209","you",48,51],["G3634","such as",52,59],["G2309","I would",60,67],["G2504","and that I",69,79],["G2147","shall be found",80,94],["G5213","unto you",95,103],["G3634","such as",104,111],["G2309","ye would",112,120],["G3756","not",121,124],["G3381","lest",126,130],["G4458","lest",126,130],["G2054","there be debates",131,147],["G2205","envyings",149,157],["G2372","wraths",159,165],["G2052","strifes",167,174],["G2636","backbitings",176,187],["G5587","whisperings",189,200],["G5450","swellings",202,211],["G0181","tumults",213,220]]},"12:21":{"text":"And lest, when I come again, my God will humble me among you, and that I shall bewail many which have sinned already, and have not repented of the uncleanness and fornication and lasciviousness which they have committed.","words":[["G3361","And lest",0,8],["G2064","when I come",10,21],["G3825","again",22,27],["G3450","my",29,31],["G2316","God",32,35],["G5013","will humble",36,47],["G3165","me",48,50],["G4314","among",51,56],["G5209","you",57,60],["G2532","and",62,65],["G3996","that I shall bewail",66,85],["G4183","many",86,90],["G3588","which",91,96],["G4258","have sinned already",97,116],["G2532","and",118,121],["G3340","have",122,126],["G3361","not",127,130],["G3340","repented",131,139],["G1909","of",140,142],["G0167","the uncleanness",143,158],["G2532","and",159,162],["G4202","fornication",163,174],["G2532","and",175,178],["G0766","lasciviousness",179,193],["G3739","which",194,199],["G4238","they have committed",200,219]]},"13:1":{"text":"This is the third time I am coming to you. In the mouth of two or three witnesses shall every word be established.","words":[["G5124","This",0,4],["G5154","is the third",5,17],["G2064","time I am coming",18,34],["G4314","to",35,37],["G5209","you",38,41],["G1909","In",43,45],["G4750","the mouth",46,55],["G1417","of two",56,62],["G2532","or",63,65],["G5140","three",66,71],["G3144","witnesses",72,81],["G2476","shall",82,87],["G3956","every",88,93],["G4487","word",94,98],["G2476","be established",99,113]]},"13:2":{"text":"I told you before, and foretell you, as if I were present, the second time; and being absent now I write to them which heretofore have sinned, and to all other, that, if I come again, I will not spare:","words":[["G4280","I told you before",0,17],["G2532","and",19,22],["G4302","foretell you",23,35],["G5613","as if",37,42],["G3918","I were present",43,57],["G1208","the second",59,69],["G2532","time; and",70,79],["G0548","being absent",80,92],["G3568","now",93,96],["G1125","I write",97,104],["G4258","to them which heretofore have sinned",105,141],["G2532","and",143,146],["G3956","to all",147,153],["G3062","other",154,159],["G3754","that",161,165],["G1437","if",167,169],["G2064","I come",170,176],["G1519","again",177,182],["G3825","again",177,182],["G5339","I will",184,190],["G3756","not",191,194],["G5339","spare",195,200]]},"13:3":{"text":"Since ye seek a proof of Christ speaking in me, which to you-ward is not weak, but is mighty in you.","words":[["G1893","Since",0,5],["G2212","ye seek",6,13],["G1382","a proof",14,21],["G5547","of Christ",22,31],["G2980","speaking",32,40],["G1722","in",41,43],["G1698","me",44,46],["G3739","which",48,53],["G1519","to",54,56],["G5209","you-ward",57,65],["G0770","is",66,68],["G3756","not",69,72],["G0770","weak",73,77],["G0235","but",79,82],["G1414","is mighty",83,92],["G1722","in",93,95],["G5213","you",96,99]]},"13:4":{"text":"For though he was crucified through weakness, yet he liveth by the power of God. For we also are weak in him, but we shall live with him by the power of God toward you.","words":[["G1063","For",0,3],["G2532","For",0,3],["G1487","though",4,10],["G4717","he was crucified",11,27],["G1537","through",28,35],["G0769","weakness",36,44],["G0235","yet",46,49],["G2198","he liveth",50,59],["G1537","by",60,62],["G1411","the power",63,72],["G2316","of God",73,79],["G1063","For",81,84],["G2249","we",85,87],["G2532","also",88,92],["G0770","are weak",93,101],["G1722","in",102,104],["G0846","him",105,108],["G0235","but",110,113],["G2198","we shall live",114,127],["G4862","with",128,132],["G0846","him",133,136],["G1537","by",137,139],["G1411","the power",140,149],["G2316","of God",150,156],["G1519","toward",157,163],["G5209","you",164,167]]},"13:5":{"text":"Examine yourselves, whether ye be in the faith; prove your own selves. Know ye not your own selves, how that Jesus Christ is in you, except ye be reprobates?","words":[["G3985","Examine",0,7],["G1438","yourselves",8,18],["G1487","whether",20,27],["G2075","ye be",28,33],["G1722","in",34,36],["G4102","the faith",37,46],["G1381","prove",48,53],["G1438","your own selves",54,69],["G2228","",-1,-1],["G1921","Know ye",71,78],["G3756","not",79,82],["G1438","your own selves",83,98],["G3754","how that",100,108],["G2424","Jesus",109,114],["G5547","Christ",115,121],["G2076","is",122,124],["G1722","in",125,127],["G5213","you",128,131],["G1509","except",133,139],["G2075","ye be",140,145],["G5100","reprobates",146,156],["G0096","reprobates",146,156]]},"13:6":{"text":"But I trust that ye shall know that we are not reprobates.","words":[["G1161","But",0,3],["G1679","I trust",4,11],["G3754","that",12,16],["G1097","ye shall know",17,30],["G3754","that",31,35],["G2249","we",36,38],["G2070","are",39,42],["G3756","not",43,46],["G0096","reprobates",47,57]]},"13:7":{"text":"Now I pray to God that ye do no evil; not that we should appear approved, but that ye should do that which is honest, though we be as reprobates.","words":[["G1161","Now",0,3],["G2172","I pray",4,10],["G4314","to",11,13],["G2316","God",14,17],["G5209","that ye",18,25],["G3361","do",26,28],["G4160","do",26,28],["G3367","no",29,31],["G2556","evil",32,36],["G3756","not",38,41],["G2443","that",42,46],["G2249","we",47,49],["G5316","should appear",50,63],["G1384","approved",64,72],["G0235","but",74,77],["G2443","that",78,82],["G5210","ye",83,85],["G4160","should do",86,95],["G2570","that which is honest",96,116],["G1161","though",118,124],["G2249","we",125,127],["G5600","be",128,130],["G5613","as",131,133],["G0096","reprobates",134,144]]},"13:8":{"text":"For we can do nothing against the truth, but for the truth.","words":[["G1063","For",0,3],["G1410","we can do",4,13],["G3756","nothing",14,21],["G5100","nothing",14,21],["G2596","against",22,29],["G0225","the truth",30,39],["G0235","but",41,44],["G5228","for",45,48],["G0225","the truth",49,58]]},"13:9":{"text":"For we are glad, when we are weak, and ye are strong: and this also we wish, even your perfection.","words":[["G1063","For",0,3],["G2249","we",4,6],["G5463","are glad",7,15],["G3752","when",17,21],["G0770","we are weak",22,33],["G1161","and",35,38],["G5210","ye",39,41],["G5600","are",42,45],["G1415","strong",46,52],["G1161","and",54,57],["G5124","this",58,62],["G2532","also",63,67],["G2172","we wish",68,75],["G5216","even your",77,86],["G2676","perfection",87,97]]},"13:10":{"text":"Therefore I write these things being absent, lest being present I should use sharpness, according to the power which the Lord hath given me to edification, and not to destruction.","words":[["G5124","Therefore",0,9],["G1223","Therefore",0,9],["G1125","I write",10,17],["G5023","these things",18,30],["G0548","being absent",31,43],["G3363","lest",45,49],["G3918","being present",50,63],["G5530","I should use",64,76],["G0664","sharpness",77,86],["G2596","according",88,97],["G1849","to the power",98,110],["G3739","which",111,116],["G2962","the Lord",117,125],["G1325","hath given",126,136],["G3427","me",137,139],["G1519","to",140,142],["G3619","edification",143,154],["G2532","and",156,159],["G3756","not",160,163],["G1519","to",164,166],["G2506","destruction",167,178]]},"13:11":{"text":"Finally, brethren, farewell. Be perfect, be of good comfort, be of one mind, live in peace; and the God of love and peace shall be with you.","words":[["G3063","Finally",0,7],["G0080","brethren",9,17],["G5463","farewell",19,27],["G2675","Be perfect",29,39],["G3870","be of good comfort",41,59],["G0846","be of one",61,70],["G5426","mind",71,75],["G1514","live in peace",77,90],["G2532","and",92,95],["G2316","the God",96,103],["G0026","of love",104,111],["G2532","and",112,115],["G1515","peace",116,121],["G2071","shall be",122,130],["G3326","with",131,135],["G5216","you",136,139]]},"13:12":{"text":"Greet one another with an holy kiss.","words":[["G0782","Greet",0,5],["G0240","one another",6,17],["G1722","with",18,22],["G0040","an holy",23,30],["G5370","kiss",31,35]]},"13:13":{"text":"All the saints salute you.","words":[["G3956","All",0,3],["G0040","the saints",4,14],["G0782","salute",15,21],["G5209","you",22,25]]},"13:14":{"text":"The grace of the Lord Jesus Christ, and the love of God, and the communion of the Holy Ghost, be with you all. Amen.","words":[["G5485","The grace",0,9],["G2962","of the Lord",10,21],["G2424","Jesus",22,27],["G5547","Christ",28,34],["G2532","and",36,39],["G0026","the love",40,48],["G2316","of God",49,55],["G2532","and",57,60],["G2842","the communion",61,74],["G0040","of the Holy",75,86],["G4151","Ghost",87,92],["G3326","be with",94,101],["G5216","you",102,105],["G3956","all",106,109],["G0281","Amen",111,115]]}}};
